    mapper: (item: any, uid: string) => any, 
    userId: string,
    idField: string = 'id'
) => {
    if (!supabaseClient) return;

    // 1. Upsert Local Items (Create & Update)
    if (localData.length > 0) {
        const batchSize = 50;
        for (let i = 0; i < localData.length; i += batchSize) {
            const chunk = localData.slice(i, i + batchSize);
            const { error: upsertError } = await supabaseClient
                .from(tableName)
                .upsert(chunk.map(item => mapper(item, userId)));
            if (upsertError) throw upsertError;
        }
    }

    // 2. Delete Remote Items NOT in Local (The CRUD Delete)
    // Fetch all remote IDs to identify what has been deleted locally
    const { data: remoteData, error: fetchError } = await supabaseClient
        .from(tableName)
        .select(idField)
        .eq('user_id', userId);

    if (fetchError) throw fetchError;

    if (remoteData) {
        const localIdSet = new Set(localData.map((d: any) => {
            // Special handling for Budget which uses monthKey property but maps to month_key DB column
            return idField === 'month_key' ? d.monthKey : d.id;
        }));

        const idsToDelete = remoteData
            .map((row: any) => row[idField])
            .filter((remoteId: string) => !localIdSet.has(remoteId));

        if (idsToDelete.length > 0) {
            console.log(`Deleting ${idsToDelete.length} items from ${tableName}...`);
            // Delete in batches
            const deleteBatchSize = 50;
            for (let i = 0; i < idsToDelete.length; i += deleteBatchSize) {
                const batch = idsToDelete.slice(i, i + deleteBatchSize);
                const { error: deleteError } = await supabaseClient
                    .from(tableName)
                    .delete()
                    .eq('user_id', userId) // Security: ensure we only delete user's data
                    .in(idField, batch);

                if (deleteError) {
                    console.error("Delete failed", deleteError);
                    throw deleteError;
                }
            }
        }
    }
}


export const supabaseService = {
  updateClient: (url: string, key: string) => {
    if (!url || !key) return;
    if (url === currentUrl && key === currentKey && supabaseClient) return;
    try {
        console.log("Updating Supabase Client connection...");
        currentUrl = url; currentKey = key;
        supabaseClient = createClient(url, key);
    } catch (e) {
        console.error("Failed to update Supabase client", e);
    }
  },

  getClient: () => supabaseClient,
  isConnected: () => !!supabaseClient, 

  auth: {
    login: async (email: string, password: string) => {
         if(!supabaseClient) return { error: { message: "Supabase not configured in Settings" } };
         return supabaseClient.auth.signInWithPassword({ email, password });
    },
    signUp: async (email: string, password: string) => {
         if(!supabaseClient) return { error: { message: "Supabase not configured in Settings" } };
         return supabaseClient.auth.signUp({ email, password });
    },
    signInWithGoogle: async () => {
         if(!supabaseClient) return { error: { message: "Supabase not configured in Settings" } };
         return supabaseClient.auth.signInWithOAuth({ provider: 'google' });
    },
    logout: async () => { if(!supabaseClient) return; return supabaseClient.auth.signOut(); },
    getUser: async () => {
        if(!supabaseClient) return null;
        const { data: { user } } = await supabaseClient.auth.getUser();
        return user;
    },
    onAuthStateChange: (callback: (event: any, session: any) => void) => {
        if(!supabaseClient) return { data: { subscription: { unsubscribe: () => {} } } };
        return supabaseClient.auth.onAuthStateChange(callback);
    }
  },

  // --- Normalized Data Methods ---
  pullData: async (userId: string): Promise<{ data: AppState | null; error: any }> => {
    if(!supabaseClient) return { data: null, error: "Client not initialized" };

    try {
      console.log(`Pulling normalized data for user: ${userId}...`);

      // Parallel fetch for speed
      const [
          accountsRes, partiesRes, transactionsRes, assetsRes, 
          receivablesRes, templatesRes, recurringRes, budgetsRes, profilesRes
      ] = await Promise.all([
          supabaseClient.from('fintrack_accounts').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_parties').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_transactions').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_assets').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_receivables').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_templates').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_recurring').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_budgets').select('*').eq('user_id', userId),
          supabaseClient.from('fintrack_profiles').select('*').eq('id', userId).maybeSingle()
      ]);

      // Check for missing table error specifically on the core tables
      if (accountsRes.error && accountsRes.error.code === '42P01') {
          return { data: null, error: "Missing Tables. Please run Setup SQL in Settings > Sync." };
      }

      // If basic fetches fail
      if (accountsRes.error) throw accountsRes.error;
      if (transactionsRes.error) throw transactionsRes.error;

      // Map to AppState
      const newState: AppState = {
          accounts: (accountsRes.data || []).map(fromDB.account),
          parties: (partiesRes.data || []).map(fromDB.party),
          transactions: (transactionsRes.data || []).map(fromDB.transaction),
          assets: (assetsRes.data || []).map(fromDB.asset),
          receivables: (receivablesRes.data || []).map(fromDB.receivable),
          templates: (templatesRes.data || []).map(fromDB.template),
          recurring: (recurringRes.data || []).map(fromDB.recurring),
          monthlyBudgets: (budgetsRes.data || []).map(fromDB.budget),
          businessProfile: profilesRes.data ? {
              name: profilesRes.data.name || 'My Business',
              address: profilesRes.data.address || '',
              phone: profilesRes.data.phone || '',
              email: profilesRes.data.email || '',
              baseCurrency: profilesRes.data.base_currency // Map base_currency
          } : { name: 'My Business', address: '', phone: '', email: '' }
      };

      // Basic empty state check - if no accounts exist, it might be a fresh user
      if (newState.accounts.length === 0) {
          console.log("No remote data found (New Account).");
          // Return null data so the app can initialize seed data locally
          return { data: null, error: null };
      }

      console.log("Data pulled successfully.");
      return { data: newState, error: null };

    } catch (e: any) {
      const msg = e.message || String(e);
      console.warn("Supabase Pull Exception:", msg); 
      return { data: null, error: msg };
    }
  },

  pushData: async (userId: string, state: AppState): Promise<{ error: any }> => {
    if(!supabaseClient) return { error: "Client not initialized" };

    try {
      console.log(`Pushing normalized data for user: ${userId}...`);

      const p = state;

      // Execute syncs SEQUENTIALLY to avoid "Failed to fetch" due to browser connection limits/congestion
      await syncTable('fintrack_accounts', p.accounts, toDB.account, userId);
      await syncTable('fintrack_parties', p.parties, toDB.party, userId);
      await syncTable('fintrack_transactions', p.transactions, toDB.transaction, userId);
      await syncTable('fintrack_assets', p.assets, toDB.asset, userId);
      await syncTable('fintrack_receivables', p.receivables, toDB.receivable, userId);
      await syncTable('fintrack_recurring', p.recurring, toDB.recurring, userId);
      await syncTable('fintrack_templates', p.templates, toDB.template, userId);

      if (p.monthlyBudgets) {
          await syncTable('fintrack_budgets', p.monthlyBudgets, toDB.budget, userId, 'month_key');
      }

      // Profile is a single row, simple upsert is fine
      await supabaseClient.from('fintrack_profiles').upsert({
          id: userId,
          name: p.businessProfile.name,
          address: p.businessProfile.address,
          phone: p.businessProfile.phone,
          email: p.businessProfile.email,
          base_currency: p.businessProfile.baseCurrency // Save baseCurrency
      });

      console.log("Data pushed successfully.");
      return { error: null };
    } catch (e: any) {
      const msg = e.message || String(e);
      console.error("Supabase Push Exception:", msg);

      if (typeof msg === 'string' && msg.includes('42P01')) {
          return { error: "Missing Tables. Please run Setup SQL in Settings > Sync." };
      }
      return { error: msg };
    }
  }
};

export const supabase = supabaseClient || createClient('https://placeholder.supabase.co', 'placeholder');

import React, { createContext, useContext, useEffect, useReducer, useRef, useState, useCallback } from 'react';
import { AppState, Account, Receivable, Transaction, TransactionTemplate, Party, Asset, SyncConfig, BusinessProfile, MonthlyBudget, RecurringTransaction, CurrencyCode } from '../types';
import { storageService } from '../services/storage';
import { supabaseService } from '../services/supabase';
import { SUPABASE_URL, SUPABASE_KEY, DEFAULT_ACCOUNTS, SEED_PARTIES, SEED_TRANSACTIONS, SEED_RECEIVABLES, SEED_ASSETS } from '../constants';
import { addMonths, addWeeks, addYears, addDays, isPast, parseISO, isBefore, format } from 'date-fns';
import { User } from '@supabase/supabase-js';
import { calculateDirectBalance } from '../utils/accountHierarchy';

// MIGRATION HELPER
const migrateState = (oldState: any): AppState => {
    let accounts: Account[] = oldState.categories || oldState.accounts || DEFAULT_ACCOUNTS;
    // Map legacy 'categories' to 'accounts' if needed
    if (oldState.categories && !oldState.accounts) {
        // Simple mapping for migration - in a real app this would be more complex
        accounts = DEFAULT_ACCOUNTS; 
    }

    let parties: Party[] = oldState.entities || oldState.parties || SEED_PARTIES;
    // ensure parties is array
    if(!Array.isArray(parties)) parties = SEED_PARTIES;

    return {
        ...oldState,
        accounts: accounts.length > 0 ? accounts : DEFAULT_ACCOUNTS,
        parties: parties,
        transactions: oldState.transactions || [],
        receivables: oldState.receivables || [],
        assets: oldState.assets || [],
        templates: oldState.templates || [],
        recurring: oldState.recurring || [],
        businessProfile: oldState.businessProfile || { name: 'My Business', address: '', email: '', phone: '', baseCurrency: undefined }
    };
};

type Action =
  | { type: 'ADD_TRANSACTION'; payload: Transaction }
  | { type: 'UPDATE_TRANSACTION'; payload: Transaction }
  | { type: 'DELETE_TRANSACTION'; payload: string }
  | { type: 'ADD_ACCOUNT'; payload: Account }
  | { type: 'UPDATE_ACCOUNT'; payload: Account }
  | { type: 'DELETE_ACCOUNT'; payload: string }
  | { type: 'ADD_RECEIVABLE'; payload: Receivable }
  | { type: 'UPDATE_RECEIVABLE'; payload: Receivable }
  | { type: 'DELETE_RECEIVABLE'; payload: string }
  | { type: 'ADD_TEMPLATE'; payload: TransactionTemplate }
  | { type: 'DELETE_TEMPLATE'; payload: string }
  | { type: 'ADD_PARTY'; payload: Party }
  | { type: 'UPDATE_PARTY'; payload: Party }
  | { type: 'DELETE_PARTY'; payload: string }
  | { type: 'ADD_ASSET'; payload: Asset }
  | { type: 'UPDATE_ASSET'; payload: Asset }
  | { type: 'DELETE_ASSET'; payload: string }
  | { type: 'UPDATE_BUSINESS_PROFILE'; payload: BusinessProfile }
  | { type: 'SET_MONTHLY_BUDGET'; payload: MonthlyBudget }
  | { type: 'ADD_RECURRING'; payload: RecurringTransaction }
  | { type: 'UPDATE_RECURRING'; payload: RecurringTransaction }
  | { type: 'DELETE_RECURRING'; payload: string }
  | { type: 'PROCESS_RECURRING_UPDATES'; payload: { transactions: Transaction[], updatedRecurring: RecurringTransaction[] } }
  | { type: 'PROCESS_ASSET_DEPRECIATION'; payload: { transactions: Transaction[], updatedAssets: Asset[] } }
  | { type: 'RESET_DATA' }
  | { type: 'SET_STATE'; payload: any }
  | { type: 'MIGRATE_BASE_CURRENCY'; payload: { newCurrency: CurrencyCode; rate: number } };

const rawState = storageService.load();
const initialState: AppState = rawState ? migrateState(rawState) : {
    transactions: SEED_TRANSACTIONS,
    accounts: DEFAULT_ACCOUNTS,
    receivables: SEED_RECEIVABLES,
    templates: [],
    recurring: [],
    parties: SEED_PARTIES,
    assets: SEED_ASSETS,
    businessProfile: { name: 'My Business', email: '', phone: '', address: '', baseCurrency: undefined }
};

const financeReducer = (state: AppState, action: Action): AppState => {
  let newState: AppState;
  const timestamp = new Date().toISOString();
  const withTime = (s: AppState) => ({ ...s, lastUpdated: timestamp });

  switch (action.type) {
    case 'SET_STATE': return migrateState(action.payload);
    case 'ADD_TRANSACTION':
      newState = withTime({ ...state, transactions: [action.payload, ...state.transactions] });
      break;
    case 'UPDATE_TRANSACTION':
      newState = withTime({ ...state, transactions: state.transactions.map(t => t.id === action.payload.id ? action.payload : t) });
      break;
    case 'DELETE_TRANSACTION':
      const txToDelete = state.transactions.find(t => t.id === action.payload);
      let updatedReceivables = state.receivables;

      // SYNC LOGIC: Journal -> AR/AP
      if (txToDelete && txToDelete.note && txToDelete.note.includes('Ref:')) {
          const parts = txToDelete.note.split('Ref:');
          if (parts.length > 1) {
              const potentialId = parts[1].trim().split(' ')[0]; // Extract ID
              if (potentialId) {
                  const lowerNote = txToDelete.note.toLowerCase();
                  if (lowerNote.includes('accrual')) {
                      // If Accrual (Origin) is deleted, delete the Receivable/Payable record entirely
                      updatedReceivables = updatedReceivables.filter(r => r.id !== potentialId);
                  } else if (lowerNote.includes('settlement')) {
                      // If Settlement (Payment) is deleted, reverse the paid amount and status
                      updatedReceivables = updatedReceivables.map(r => {
                          if (r.id === potentialId) {
                              const newPaid = Math.max(0, (r.paidAmount || 0) - txToDelete.amount);
                              return {
                                  ...r,
                                  paidAmount: newPaid,
                                  status: 'pending', // Revert to pending
                                  paidDate: undefined
                              };
                          }
                          return r;
                      });
                  }
              }
          }
      }

      newState = withTime({ 
          ...state, 
          transactions: state.transactions.filter(t => t.id !== action.payload),
          receivables: updatedReceivables
      });
      break;
    case 'ADD_ACCOUNT':
      newState = withTime({ ...state, accounts: [...state.accounts, action.payload] });
      break;
    case 'UPDATE_ACCOUNT':
      newState = withTime({ ...state, accounts: state.accounts.map(c => c.id === action.payload.id ? action.payload : c) });
      break;
    case 'DELETE_ACCOUNT':
      newState = withTime({ ...state, accounts: state.accounts.filter(c => c.id !== action.payload) });
      break;
    case 'ADD_RECEIVABLE':
      newState = withTime({ ...state, receivables: [action.payload, ...state.receivables] });
      break;
    case 'UPDATE_RECEIVABLE':
      newState = withTime({ ...state, receivables: state.receivables.map(r => r.id === action.payload.id ? action.payload : r) });
      break;
    case 'DELETE_RECEIVABLE':
      const recId = action.payload;
      // SYNC LOGIC: AR/AP -> Journal
      // Delete any transactions that reference this ID
      newState = withTime({ 
          ...state, 
          receivables: state.receivables.filter(r => r.id !== action.payload),
          transactions: state.transactions.filter(t => !t.note?.includes(`Ref:${recId}`))
      });
      break;
    case 'ADD_TEMPLATE':
      newState = withTime({ ...state, templates: [...state.templates, action.payload] });
      break;
    case 'DELETE_TEMPLATE':
      newState = withTime({ ...state, templates: state.templates.filter(t => t.id !== action.payload) });
      break;
    case 'ADD_PARTY':
      newState = withTime({ ...state, parties: [...state.parties, action.payload] });
      break;
    case 'UPDATE_PARTY':
      newState = withTime({ ...state, parties: state.parties.map(e => e.id === action.payload.id ? action.payload : e) });
      break;
    case 'DELETE_PARTY':
      newState = withTime({ ...state, parties: state.parties.filter(e => e.id !== action.payload) });
      break;
    case 'ADD_ASSET':
      newState = withTime({ ...state, assets: [...state.assets, action.payload] });
      break;
    case 'UPDATE_ASSET':
      newState = withTime({ ...state, assets: state.assets.map(a => a.id === action.payload.id ? action.payload : a) });
      break;
    case 'DELETE_ASSET':
      newState = withTime({ ...state, assets: state.assets.filter(a => a.id !== action.payload) });
      break;
    case 'UPDATE_BUSINESS_PROFILE':
      newState = withTime({ ...state, businessProfile: action.payload });
      break;
    case 'SET_MONTHLY_BUDGET':
      const budgets = state.monthlyBudgets || [];
      const existingIndex = budgets.findIndex(b => b.monthKey === action.payload.monthKey);
      let newBudgets;
      if (existingIndex >= 0) {
          const existing = budgets[existingIndex];
          newBudgets = [...budgets];
          newBudgets[existingIndex] = action.payload;
      } else {
          newBudgets = [...budgets, action.payload];
      }
      newState = withTime({ ...state, monthlyBudgets: newBudgets });
      break;
    case 'ADD_RECURRING':
      const currentRec = state.recurring || [];
      newState = withTime({ ...state, recurring: [...currentRec, action.payload] });
      break;
    case 'UPDATE_RECURRING':
      newState = withTime({ ...state, recurring: (state.recurring || []).map(r => r.id === action.payload.id ? action.payload : r) });
      break;
    case 'DELETE_RECURRING':
      newState = withTime({ ...state, recurring: (state.recurring || []).filter(r => r.id !== action.payload) });
      break;
    case 'PROCESS_RECURRING_UPDATES':
        newState = withTime({
            ...state,
            transactions: [...action.payload.transactions, ...state.transactions],
            recurring: state.recurring.map(r => {
                const updated = action.payload.updatedRecurring.find(ur => ur.id === r.id);
                return updated || r;
            })
        });
        break;

    case 'PROCESS_ASSET_DEPRECIATION':
        newState = withTime({
            ...state,
            transactions: [...action.payload.transactions, ...state.transactions],
            assets: state.assets.map(a => {
                const updated = action.payload.updatedAssets.find(ua => ua.id === a.id);
                return updated || a;
            })
        });
        break;

    case 'MIGRATE_BASE_CURRENCY':
        const { newCurrency, rate } = action.payload;
        // 1. Update Profile
        const updatedProfile = { ...state.businessProfile, baseCurrency: newCurrency };

        // 2. Recalculate Transactions (Base Amount)
        // We preserve originalAmount and update 'amount' (base normalized)
        const updatedTransactions = state.transactions.map(t => ({
            ...t,
            amount: t.originalAmount ? (t.originalAmount * rate) : (t.amount * rate)
        }));

        // 3. Recalculate Assets
        const updatedAssetsMigrated = state.assets.map(a => ({
            ...a,
            value: a.value * rate, // Book Value
            originalValue: a.originalValue * rate // Original Cost
        }));

        // 4. Recalculate Receivables
        const updatedReceivablesMigrated = state.receivables.map(r => ({
            ...r,
            amount: r.amount * rate,
            paidAmount: r.paidAmount ? r.paidAmount * rate : 0
        }));

        newState = withTime({
            ...state,
            businessProfile: updatedProfile,
            transactions: updatedTransactions,
            assets: updatedAssetsMigrated,
            receivables: updatedReceivablesMigrated
        });
        break;

    case 'RESET_DATA':
      storageService.clear(); 
      newState = { ...initialState, lastUpdated: new Date(0).toISOString() };
      break;
    default:
      return state;
  }

  storageService.save(newState);
  return newState;
};

interface FinanceContextType {
  state: AppState;
  dispatch: React.Dispatch<Action>;
  syncConfig: SyncConfig;
  updateSyncConfig: (cfg: SyncConfig) => void;
  refreshData: () => Promise<void>;
  pushDataManual: () => Promise<void>;
  syncStatus: 'offline' | 'syncing' | 'synced' | 'error';
  lastError?: string;
  user: User | null;
  authLoading: boolean;
  authMethods: {
      login: (e: string, p: string) => Promise<any>;
      signUp: (e: string, p: string) => Promise<any>;
      signInWithGoogle: () => Promise<any>;
      logout: () => Promise<void>;
  };
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, dispatch] = useReducer(financeReducer, initialState);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const [syncConfig, setSyncConfig] = useState<SyncConfig>(() => {
    const saved = storageService.loadSyncConfig();
    return saved || { supabaseUrl: SUPABASE_URL, supabaseKey: SUPABASE_KEY, enabled: true };
  });

  const [syncStatus, setSyncStatus] = useState<'offline' | 'syncing' | 'synced' | 'error'>('offline');
  const [lastError, setLastError] = useState<string | undefined>(undefined);
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  const isRemoteUpdate = useRef(false);
  const isPullingRef = useRef(false); 

  useEffect(() => {
    let timeout: ReturnType<typeof setTimeout>;
    if (syncStatus === 'syncing') {
        timeout = setTimeout(() => {
            console.warn("Sync timed out");
            setSyncStatus(navigator.onLine ? 'synced' : 'offline'); 
            isPullingRef.current = false; 
        }, 10000); 
    }
    return () => clearTimeout(timeout);
  }, [syncStatus]);

  const performPull = useCallback(async (currentUser: User) => {
    if (!navigator.onLine || !currentUser) { setSyncStatus('offline'); return; }
    if (isPullingRef.current) return; 

    isPullingRef.current = true;
    setSyncStatus('syncing');
    setLastError(undefined);

    try {
        const { data, error } = await supabaseService.pullData(currentUser.id);

        if (error) {
            console.warn("Sync Pull Error:", error);
            if (String(error).includes('404') || String(error).includes('406') || String(error).includes('PGRST116')) {
                 console.log("New user detected, pushing seed data.");
                 const { error: pushError } = await supabaseService.pushData(currentUser.id, stateRef.current);
                 if (pushError) setLastError(String(pushError));
                 setSyncStatus('synced');
            } else {
                 setLastError(String(error));
                 setSyncStatus('error');
            }
        } else if (data) {
            isRemoteUpdate.current = true;
            // Ensure migration happens on pull
            dispatch({ type: 'SET_STATE', payload: data });
            console.log("Loaded user data successfully");
            setSyncStatus('synced');
        } else {
             setSyncStatus('synced');
        }
    } catch (e) {
        console.error("Pull execution error:", e);
        setSyncStatus('error');
    } finally {
        isPullingRef.current = false;
    }
  }, []); 

  // AUTH & INITIALIZATION
  useEffect(() => {
    if (syncConfig.supabaseUrl && syncConfig.supabaseKey) {
        supabaseService.updateClient(syncConfig.supabaseUrl, syncConfig.supabaseKey);
    }

    const { data: { subscription } } = supabaseService.auth.onAuthStateChange(async (event, session) => {
        const currentUser = session?.user ?? null;
        setUser(currentUser);
        setAuthLoading(false); 

        if (event === 'SIGNED_IN' && currentUser) {
            performPull(currentUser); 
        } else if (event === 'SIGNED_OUT') {
            dispatch({ type: 'RESET_DATA' });
            setSyncStatus('offline');
            setUser(null);
            isPullingRef.current = false;
        }
    });

    supabaseService.auth.getUser().then((currentUser) => {
        setAuthLoading(false); 
        if (currentUser) {
            setUser(currentUser);
            performPull(currentUser);
        }
    });

    return () => {
        subscription.unsubscribe();
    };
  }, [syncConfig, performPull]); 

  // Check online status
  useEffect(() => {
    const handleOnline = () => { if(user) setSyncStatus('synced'); };
    const handleOffline = () => setSyncStatus('offline');
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
        window.removeEventListener('online', handleOnline);
        window.removeEventListener('offline', handleOffline);
    };
  }, [user]);

  // Automated Checks (Recurring & Depreciation)
  useEffect(() => {
      const recurringRules = state.recurring || [];
      const hasAssets = state.assets && state.assets.length > 0;

      if (recurringRules.length === 0 && !hasAssets) return;

      const now = new Date();
      const newRecTransactions: Transaction[] = [];
      const updatedRecurring: RecurringTransaction[] = [];

      recurringRules.forEach(rule => {
          if (rule.active && rule.nextDueDate) {
              const dueDate = parseISO(rule.nextDueDate);
              if (isPast(dueDate)) {
                  newRecTransactions.push({
                      id: Math.random().toString(36).substr(2, 9),
                      date: new Date().toISOString(), 
                      type: rule.type,
                      amount: rule.amount,
                      currency: rule.currency,
                      originalAmount: rule.originalAmount,
                      accountId: rule.accountId,
                      source: rule.source,
                      paymentAccountId: rule.paymentAccountId,
                      relatedPartyId: rule.partyId,
                      note: `Recurring: ${rule.note || 'Auto Transaction'}`
                  });

                  // STRICT DATE CALCULATION FOR AUTOMATED SCHEDULER
                  const dateStr = rule.nextDueDate.split('T')[0];
                  const baseDate = new Date(dateStr + 'T00:00:00.000Z');

                  let nextDate = baseDate;
                  if (rule.frequency === 'daily') nextDate = addDays(baseDate, 1);
                  if (rule.frequency === 'weekly') nextDate = addWeeks(baseDate, 1);
                  if (rule.frequency === 'monthly') nextDate = addMonths(baseDate, 1);
                  if (rule.frequency === 'yearly') nextDate = addYears(baseDate, 1);

                  updatedRecurring.push({
                      ...rule,
                      lastRunDate: new Date().toISOString(),
                      nextDueDate: nextDate.toISOString()
                  });
              }
          }
      });

      if (newRecTransactions.length > 0) {
          dispatch({ type: 'PROCESS_RECURRING_UPDATES', payload: { transactions: newRecTransactions, updatedRecurring } });
      }

      // --- DYNAMIC DEPRECIATION LOGIC ---
      const newDepTransactions: Transaction[] = [];
      const updatedAssets: Asset[] = [];

      const depExpAccount = state.accounts.find(c => c.code === '60900');
      const globalAccumDepAccount = state.accounts.find(c => c.code === '12900');

      if (depExpAccount && state.assets) {
          state.assets.forEach(asset => {
              let specificAccumDep = state.accounts.find(a => a.name === `Accum Dep - ${asset.name}`);
              const targetCreditAccount = specificAccumDep || globalAccumDepAccount;

              if (!targetCreditAccount) return; 

              let currentBookValue = 0;
              let totalDepreciatedLedger = 0;

              if (specificAccumDep) {
                  totalDepreciatedLedger = calculateDirectBalance(specificAccumDep.id, state.transactions, 'credit');
                  currentBookValue = asset.originalValue - totalDepreciatedLedger;
              } else {
                  currentBookValue = asset.value;
              }

              if (currentBookValue <= 0.01) return; // Fully depreciated

              const monthlyAmount = asset.originalValue / (asset.usefulLifeYears * 12);

              let nextRunDate = asset.lastDepreciationDate 
                  ? addMonths(parseISO(asset.lastDepreciationDate), 1)
                  : addMonths(parseISO(asset.purchaseDate), 1); 

              let lastRun = asset.lastDepreciationDate;
              let hasUpdates = false;
              let tempBookValue = currentBookValue;

              while (isBefore(nextRunDate, now)) {
                  if (tempBookValue <= 0.01) break;

                  const amountToDepreciate = Math.min(monthlyAmount, tempBookValue);

                  hasUpdates = true;
                  newDepTransactions.push({
                      id: Math.random().toString(36).substr(2, 9),
                      date: nextRunDate.toISOString(),
                      type: 'expense',
                      accountId: depExpAccount.id, // Debit Expense
                      paymentAccountId: targetCreditAccount.id, // Credit Specific or Global Accum Dep
                      amount: amountToDepreciate,
                      currency: asset.currency,
                      originalAmount: amountToDepreciate,
                      source: 'personal',
                      note: `Auto Depreciation: ${asset.name} (${format(nextRunDate, 'MMM yyyy')})`
                  });

                  tempBookValue -= amountToDepreciate;
                  lastRun = nextRunDate.toISOString();
                  nextRunDate = addMonths(nextRunDate, 1);
              }

              if (hasUpdates) {
                  updatedAssets.push({ 
                      ...asset, 
                      value: Math.max(0, tempBookValue), 
                      lastDepreciationDate: lastRun 
                  });
              }
          });

          if (newDepTransactions.length > 0) {
              dispatch({ type: 'PROCESS_ASSET_DEPRECIATION', payload: { transactions: newDepTransactions, updatedAssets } });
          }
      }

  }, [state.accounts, state.assets, state.recurring, state.transactions.length]);

  // Push on state change
  useEffect(() => {
    if (syncStatus === 'offline' || !navigator.onLine || !user) return;
    if (syncStatus === 'syncing') return; 

    if (isRemoteUpdate.current) { isRemoteUpdate.current = false; return; }
    if (syncStatus === 'error') return; 

    const push = async () => {
      if (isPullingRef.current) return; 
      setSyncStatus('syncing');
      setLastError(undefined);
      const { error } = await supabaseService.pushData(user.id, state);
      if (error) {
        setLastError(String(error));
        setSyncStatus('error');
      } else {
        setSyncStatus('synced');
      }
    };
    const timeout = setTimeout(push, 3000); 
    return () => clearTimeout(timeout);
  }, [state]); 

  const pushDataManual = async () => {
      if(!user) return;
      setSyncStatus('syncing');
      const { error } = await supabaseService.pushData(user.id, state);
      if (error) { setSyncStatus('error'); alert("Upload Failed: " + (error.message || error)); } 
      else { setSyncStatus('synced'); alert("Upload Successful!"); }
  }

  const updateSyncConfig = (cfg: SyncConfig) => {
    setSyncConfig(cfg);
    storageService.saveSyncConfig(cfg); 
  };

  const refreshData = async () => {
      if (user) await performPull(user);
  };

  const authMethods = {
      login: (e: string, p: string) => supabaseService.auth.login(e, p),
      signUp: (e: string, p: string) => supabaseService.auth.signUp(e, p),
      signInWithGoogle: () => supabaseService.auth.signInWithGoogle(),
      logout: async () => {
          setUser(null);
          setSyncStatus('offline');
          dispatch({ type: 'RESET_DATA' });
          isPullingRef.current = false;
          try {
            await supabaseService.auth.logout();
          } catch (e) {
            console.error("Supabase logout warning:", e);
          }
      }
  };

  return (
    <FinanceContext.Provider value={{ state, dispatch, syncConfig, updateSyncConfig, refreshData, pushDataManual, syncStatus, lastError, user, authLoading, authMethods }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { TransactionType, SourceType, Transaction, CurrencyCode, RecurrenceFrequency, RecurringTransaction, TransactionTemplate } from '../types';
import { CURRENCIES } from '../constants';
import { Check, ArrowRightLeft, LayoutGrid, List, Save, ArrowRight, Repeat, Star, Tag } from 'lucide-react';
import { addDays, addMonths, addWeeks, addYears } from 'date-fns';
import { SearchableSelect } from './ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';

interface TransactionFormProps {
  onComplete: () => void;
  initialType?: TransactionType;
  initialData?: Transaction | null;
  mode?: 'transaction' | 'template';
  onSaveTemplate?: (template: TransactionTemplate) => void;
  initialTemplate?: TransactionTemplate | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ 
    onComplete, 
    initialType = 'expense', 
    initialData, 
    mode = 'transaction',
    onSaveTemplate,
    initialTemplate
}) => {
  const { state, dispatch } = useFinance();
  const baseCurrency = state.businessProfile.baseCurrency || 'USD';

  // Helper for Local YYYY-MM-DD
  const getTodayLocal = () => {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  // Template specific state
  const [templateName, setTemplateName] = useState(initialTemplate?.name || '');
  const [templateIcon, setTemplateIcon] = useState(initialTemplate?.icon || '⚡');

  // Shared state
  const [type, setType] = useState<TransactionType>(initialData?.type || initialType);
  const [amount, setAmount] = useState(
      initialData ? (initialData.originalAmount || initialData.amount).toString() : 
      (initialTemplate ? (initialTemplate.amount || '').toString() : '')
  );

  // Default currency to Base Currency if not provided
  const [currency, setCurrency] = useState<CurrencyCode>(initialData?.currency || initialTemplate?.currency || baseCurrency);

  const [accountId, setAccountId] = useState(initialData?.accountId || initialTemplate?.accountId || '');
  const [source, setSource] = useState<SourceType>(initialData?.source || initialTemplate?.source || 'personal');
  const [paymentAccountId, setPaymentAccountId] = useState(initialData?.paymentAccountId || initialTemplate?.paymentAccountId || '');
  // Fix: Use local date for default to avoid timezone shift errors
  const [date, setDate] = useState(initialData ? initialData.date.split('T')[0] : getTodayLocal());
  const [note, setNote] = useState(initialData?.note || initialTemplate?.note || '');
  const [partyId, setPartyId] = useState(initialData?.relatedPartyId || initialTemplate?.partyId || '');

  // Recurrence State (Transaction Mode Only)
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  const [viewMode, setViewMode] = useState<'form' | 'pos'>('pos');

  useEffect(() => {
    if (initialData || initialTemplate || mode === 'template') {
        setViewMode('form');

        // Infer Type from Account Class for Templates if not explicit
        if (mode === 'template' && accountId) {
             const acc = state.accounts.find(a => a.id === accountId);
             if (acc) {
                 if (acc.class === 'Revenue' || acc.class === 'Equity') setType('income');
                 else if (acc.class === 'Expenses' || acc.class === 'Liabilities') setType('expense');
             }
        }

        // Logic to swap UI fields for Income if editing existing data
        if (initialData && initialData.type === 'income' && !state.accounts.find(a => a.id === initialData.accountId)?.class.includes('Revenue')) {
             setAccountId(initialData.paymentAccountId || '');
             setPaymentAccountId(initialData.accountId);
        }
    } else {
        const isMobile = window.innerWidth < 768;
        if(isMobile) setViewMode('pos');
    }
  }, [initialData, initialTemplate, state.accounts, mode]);

  // AUTO-SET DEFAULT PAYMENT ACCOUNT
  useEffect(() => {
      if (initialData || initialTemplate) return; 
      // Only auto-select if it's a Sub-Ledger. 
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank') && c.level === 'sub_ledger');
      const cash = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('cash') && c.level === 'sub_ledger');

      if (type === 'expense') {
          if (bank) setPaymentAccountId(bank.id);
      } else if (type === 'income') {
          if (cash) setPaymentAccountId(cash.id);
      } else if (type === 'transfer') {
          if (bank) setPaymentAccountId(bank.id);
      }
  }, [type, state.accounts, initialData, initialTemplate]);

  // DATA TRANSFORMATION FOR SEARCHABLE SELECT
  const availableAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // STRICT RULE: User only allowed to use Sub-Ledgers
          if (c.level !== 'sub_ledger') return false;

          if (type === 'transfer') return true; 

          if (type === 'expense') return c.class === 'Expenses' || c.class === 'Liabilities' || c.class === 'Assets'; 
          if (type === 'income') return c.class === 'Revenue' || c.class === 'Equity';

          return true;
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  const availableParties = state.parties
      .filter(e => e.type === (type === 'income' ? 'customer' : 'vendor'))
      .map(e => ({ id: e.id, label: e.name }));

  const transferSourceAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // STRICT RULE: User only allowed to use Sub-Ledgers
          if (c.level !== 'sub_ledger') return false;

          if (type === 'transfer') return true;
          return c.class === 'Assets'; 
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  // Organize Currencies: Base Currency first, then others
  const sortedCurrencies = [...CURRENCIES].sort((a, b) => {
      if (a.code === baseCurrency) return -1;
      if (b.code === baseCurrency) return 1;
      return a.code.localeCompare(b.code);
  });

  const selectedCurrencySymbol = CURRENCIES.find(c => c.code === currency)?.symbol || '$';

  const handleAccountChange = (id: string) => {
    setAccountId(id);
  };

  const handleTemplateClick = (templateId: string) => {
      const t = state.templates.find(temp => temp.id === templateId);
      if(!t) return;

      const acc = state.accounts.find(c => c.id === t.accountId);
      if(acc) {
        const targetType = (acc.class === 'Assets' || acc.class === 'Liabilities') ? 'expense' : (acc.class === 'Revenue' ? 'income' : 'expense');
        setType(targetType as TransactionType);
        setAccountId(acc.id);
        if (t.source) setSource(t.source);
      }

      if(t.amount) setAmount(t.amount.toString());
      setCurrency(t.currency);
      if(t.note) setNote(t.note);
      if(t.partyId) setPartyId(t.partyId);
      if(t.paymentAccountId) setPaymentAccountId(t.paymentAccountId);

      setViewMode('form'); 
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);

    if (!finalAmountStr && mode === 'transaction') return; // Amount mandatory for transaction
    if (!accountId) { alert('Please select a main category/account.'); return; }

    if (type === 'transfer' && !paymentAccountId) {
        alert("Please select a 'From' account.");
        return;
    }
    if (type === 'transfer' && accountId === paymentAccountId) {
        alert("From and To accounts cannot be the same.");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr) || 0;

    // NOTE: In a real multi-currency system, we would ask for exchange rate if Currency != BaseCurrency.
    // For now, we assume direct entry relative to Base Currency or user handles conversion logic via input expression.
    // However, to respect the "Base Amount" field, if currency matches base, it's 1:1.
    // If different, we ideally prompt. For this specific implementation scope, we treat input amount as raw
    // and store it. The `amount` field in DB is meant to be Normalized.
    // We will just store inputAmount as amount for now unless we add an exchange rate picker.
    // Since the prompt emphasizes "Data Integrity", storing accurate original_amount is key.

    const finalAmountBase = inputAmount; // Simplified: Assuming user enters base equivalent or 1:1 for now

    // --- CRITICAL ACCOUNTING LOGIC ---
    let finalDebitAccount = accountId;
    let finalCreditAccount = paymentAccountId;

    if (type === 'income') {
        finalDebitAccount = paymentAccountId; // Bank becomes Dr
        finalCreditAccount = accountId;      // Revenue becomes Cr
    } 

    // --- TEMPLATE SAVE MODE ---
    if (mode === 'template') {
        if (!templateName) { alert('Please name your shortcut.'); return; }
        const templateData: TransactionTemplate = {
            id: initialTemplate?.id || Math.random().toString(36).substr(2, 9),
            name: templateName,
            icon: templateIcon,
            accountId: accountId, // Store the user selected account ID (Category), not the resolved debit/credit
            amount: inputAmount || undefined, // Optional in template
            currency: currency,
            note: note,
            partyId: partyId || undefined,
            paymentAccountId: paymentAccountId || undefined,
            source: source
        };
        if (onSaveTemplate) onSaveTemplate(templateData);
        onComplete();
        return;
    }

    // --- TRANSACTION SAVE MODE ---
    if (isNaN(inputAmount) || inputAmount <= 0) {
        alert("Invalid amount");
        return;
    }

    const transactionData: Transaction = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      date: new Date(date).toISOString(),
      type,
      amount: finalAmountBase, // This should technically be the converted amount to base
      originalAmount: inputAmount,
      currency: currency,
      accountId: finalDebitAccount, // DEBIT
      source,
      paymentAccountId: finalCreditAccount || undefined, // CREDIT
      note,
      relatedPartyId: partyId || undefined
    };

    if (initialData) {
        dispatch({ type: 'UPDATE_TRANSACTION', payload: transactionData });
    } else {
        dispatch({ type: 'ADD_TRANSACTION', payload: transactionData });

        if (isRecurring) {
            // STRICT DATE CALCULATION
            const baseDate = new Date(date + 'T00:00:00.000Z');
            let nextDate = baseDate;

            if (recurFreq === 'daily') nextDate = addDays(baseDate, 1);
            if (recurFreq === 'weekly') nextDate = addWeeks(baseDate, 1);
            if (recurFreq === 'monthly') nextDate = addMonths(baseDate, 1);
            if (recurFreq === 'yearly') nextDate = addYears(baseDate, 1);

            const recurringRule: RecurringTransaction = {
                id: Math.random().toString(36).substr(2, 9),
                active: true,
                type,
                accountId: finalDebitAccount,
                amount: finalAmountBase,
                originalAmount: inputAmount,
                currency,
                source,
                paymentAccountId: finalCreditAccount || undefined,
                partyId: partyId || undefined,
                note: note,
                frequency: recurFreq,
                nextDueDate: nextDate.toISOString()
            };

            dispatch({ type: 'ADD_RECURRING', payload: recurringRule });
            // Use local string for alert to be friendly
            alert(`Recurring rule created. Next due: ${nextDate.toISOString().split('T')[0]}`);
        }
    }
    onComplete();
  };

  return (
    <div className="space-y-4">
        {!initialData && mode === 'transaction' && (
            <div className="flex justify-end mb-2">
                <button 
                    onClick={() => setViewMode(viewMode === 'form' ? 'pos' : 'form')}
                    className="text-xs flex items-center gap-1.5 text-primary hover:text-blue-400 font-bold px-4 py-2.5 bg-gray-800 rounded-xl border border-gray-700 glass-card btn-float active:scale-95"
                >
                    {viewMode === 'form' ? <><LayoutGrid size={16} /> Use Shortcuts</> : <><List size={16} /> Manual Entry</>}
                </button>
            </div>
        )}

        {viewMode === 'pos' && !initialData && mode === 'transaction' ? (
            <div className="grid grid-cols-2 gap-3 max-h-[60vh] overflow-y-auto no-scrollbar pb-4">
                {state.templates.length === 0 && (
                    <div className="col-span-2 text-center py-12 text-gray-500 text-sm border border-dashed border-gray-700 rounded-2xl flex flex-col items-center gap-3">
                        <LayoutGrid size={32} className="opacity-20" />
                        <div>No shortcuts configured.<br/>Add them in Settings.</div>
                    </div>
                )}
                {state.templates.map(t => {
                    const tSym = CURRENCIES.find(c => c.code === t.currency)?.symbol || '$';
                    return (
                        <button
                            key={t.id}
                            onClick={() => handleTemplateClick(t.id)}
                            className="flex flex-col items-center justify-center p-5 bg-gray-800/60 backdrop-blur-md border border-gray-700 hover:border-primary hover:bg-gray-800/80 rounded-2xl transition-all active:scale-95 btn-float group"
                        >
                            <span className="text-4xl mb-3 group-hover:scale-110 transition-transform">{t.icon || '⚡'}</span>
                            <span className="text-sm font-bold text-gray-100 tracking-tight">{t.name}</span>
                            {t.amount && (
                            <span className="text-[10px] text-gold-500/80 font-mono mt-1 px-1.5 py-0.5 bg-gold-500/5 rounded border border-gold-500/10">
                                {tSym}{t.amount.toLocaleString()}
                            </span>
                            )}
                        </button>
                    );
                })}
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="space-y-5 animate-fade-in">

                {/* QUICK SHORTCUTS FOR ACCRUALS */}
                {mode === 'transaction' && !initialData && (
                    <div className="grid grid-cols-3 gap-3 mb-2">
                        <button 
                            type="button" 
                            onClick={() => {
                                setType('income');
                                // Try to find AR account (Sub-ledger)
                                const ar = state.accounts.find(a => a.name.toLowerCase().includes('receivable') && a.level === 'sub_ledger');
                                if (ar) setPaymentAccountId(ar.id);
                                setNote('Invoice Accrual');
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-emerald-500/10 to-teal-600/10 hover:from-emerald-500/30 hover:to-teal-600/30 border border-emerald-500/20 hover:border-emerald-500/50 text-emerald-400 transition-all active:scale-95 shadow-lg shadow-emerald-900/5 backdrop-blur-md"
                        >
                            AR
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                setType('expense');
                                // Try to find AP account (Sub-ledger)
                                const ap = state.accounts.find(a => a.name.toLowerCase().includes('payable') && a.level === 'sub_ledger');
                                if (ap) setPaymentAccountId(ap.id);
                                setNote('Bill Accrual');
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-red-500/10 to-orange-600/10 hover:from-red-500/30 hover:to-orange-600/30 border border-red-500/20 hover:border-red-500/50 text-red-400 transition-all active:scale-95 shadow-lg shadow-red-900/5 backdrop-blur-md"
                        >
                            AP
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                setType('expense');
                                // Payment: Dr AP, Cr Bank
                                const ap = state.accounts.find(a => a.name.toLowerCase().includes('payable') && a.level === 'sub_ledger');
                                const bank = state.accounts.find(a => a.name.toLowerCase().includes('bank') && a.level === 'sub_ledger');
                                if (ap) setAccountId(ap.id);
                                if (bank) setPaymentAccountId(bank.id);
                                setNote('Bill Payment');
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-purple-500/10 to-indigo-600/10 hover:from-purple-500/30 hover:to-indigo-600/30 border border-purple-500/20 hover:border-purple-500/50 text-purple-400 transition-all active:scale-95 shadow-lg shadow-purple-900/5 backdrop-blur-md"
                        >
                            P
                        </button>
                    </div>
                )}

                {/* TEMPLATE HEADER FIELDS */}
                {mode === 'template' && (
                    <div className="bg-indigo-900/20 p-4 rounded-xl border border-indigo-500/30 space-y-4 mb-2">
                        <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                            <Star size={14} /> Shortcut Details
                        </h4>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Shortcut Name</label>
                            <input 
                                type="text" 
                                value={templateName} 
                                onChange={e => setTemplateName(e.target.value)} 
                                className="w-full px-4 py-2.5 bg-gray-950 text-white border border-gray-700 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                                placeholder="e.g. Morning Coffee"
                                autoFocus
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Icon / Emoji</label>
                            <div className="flex gap-2">
                                {['⚡','☕','⛽','🛒','🍔','🚗','🏠','💊','✈️','🎓'].map(icon => (
                                    <button 
                                        type="button" 
                                        key={icon} 
                                        onClick={() => setTemplateIcon(icon)}
                                        className={`w-10 h-10 rounded-lg flex items-center justify-center text-xl transition-colors ${templateIcon === icon ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                                    >
                                        {icon}
                                    </button>
                                ))}
                                <input 
                                    type="text" 
                                    value={templateIcon} 
                                    onChange={e => setTemplateIcon(e.target.value)} 
                                    className="w-12 h-10 text-center bg-gray-950 border border-gray-700 rounded-lg text-white" 
                                    placeholder="?"
                                />
                            </div>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-3 gap-2 p-1.5 bg-gray-900/50 rounded-2xl border border-gray-700">
                    <button type="button" onClick={() => { setType('expense'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'expense' ? 'bg-gray-700 text-red-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Expense</button>
                    <button type="button" onClick={() => { setType('income'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'income' ? 'bg-gray-700 text-emerald-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Income</button>
                    <button type="button" onClick={() => { setType('transfer'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'transfer' ? 'bg-gray-700 text-blue-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Transfer</button>
                </div>

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Amount {mode === 'template' && '(Optional)'}</label>
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gold-500 text-xl font-bold">{selectedCurrencySymbol}</span>
                        <input 
                            type="text" 
                            inputMode="decimal"
                            value={amount} 
                            onChange={(e) => setAmount(e.target.value)} 
                            onBlur={handleAmountBlur}
                            className="w-full pl-12 pr-4 py-4 text-3xl font-bold text-white bg-gray-950 border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary focus:border-transparent outline-none placeholder-gray-800" 
                            placeholder={mode === 'template' ? "0.00 (Optional)" : "0.00"}
                            required={mode === 'transaction'}
                        />
                        </div>
                        <div className="w-24">
                            <select 
                                value={currency} 
                                onChange={(e) => setCurrency(e.target.value as CurrencyCode)} 
                                className="w-full h-full px-2 bg-gray-950 text-white border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary outline-none font-bold text-center appearance-none"
                            >
                                {sortedCurrencies.map(c => (
                                    <option key={c.code} value={c.code}>{c.code}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>

                {type === 'transfer' ? (
                     <div className="grid grid-cols-1 gap-5 p-5 bg-blue-900/10 border border-blue-500/20 rounded-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-3 opacity-5">
                          <ArrowRightLeft size={64} className="text-blue-500" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">From Account (Credit)</label>
                            <SearchableSelect
                                options={transferSourceAccounts}
                                value={paymentAccountId}
                                onChange={setPaymentAccountId}
                                placeholder="Select Source..."
                                required
                            />
                        </div>
                        <div className="flex justify-center -my-3 relative z-10">
                            <div className="bg-gray-900 border border-blue-500/30 p-2 rounded-full shadow-lg">
                              <ArrowRight className="text-blue-500 rotate-90" size={16} />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">To Account (Debit)</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Destination..."
                                required
                            />
                        </div>
                     </div>
                ) : (
                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Classification ({type === 'income' ? 'Revenue' : 'Expense'})</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Account..."
                                required
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Payment via</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'None'}, ...transferSourceAccounts]}
                                    value={paymentAccountId}
                                    onChange={setPaymentAccountId}
                                    placeholder="Source..."
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1 truncate">{type === 'income' ? 'Payer' : 'Merchant'}</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'Opt...'}, ...availableParties]}
                                    value={partyId}
                                    onChange={setPartyId}
                                    placeholder="Party..."
                                />
                            </div>
                        </div>
                    </div>
                )}

                {mode === 'transaction' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Effective Date</label>
                            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3.5 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none" />
                        </div>
                    </div>
                )}

                {!initialData && mode === 'transaction' && (
                    <div className="p-4 bg-gray-950/50 rounded-2xl border border-gray-800">
                        <div className="flex items-center gap-3 mb-2">
                            <input 
                                type="checkbox" 
                                id="isRecurring"
                                checked={isRecurring} 
                                onChange={e => setIsRecurring(e.target.checked)} 
                                className="w-5 h-5 rounded-lg bg-gray-900 border-gray-700 focus:ring-primary text-primary" 
                            />
                            <label htmlFor="isRecurring" className="text-sm font-bold text-gray-300 flex items-center gap-2 cursor-pointer">
                                <Repeat size={14} className="text-gold-500" />
                                Automate Transaction?
                            </label>
                        </div>
                        {isRecurring && (
                            <div className="flex items-center gap-3 animate-fade-in pl-8 mt-2">
                                <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">Interval:</span>
                                <select 
                                    className="px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white text-xs outline-none focus:border-gold-500 font-bold uppercase" 
                                    value={recurFreq} 
                                    onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)}
                                >
                                    <option value="daily">Daily</option>
                                    <option value="weekly">Weekly</option>
                                    <option value="monthly">Monthly</option>
                                    <option value="yearly">Yearly</option>
                                </select>
                            </div>
                        )}
                    </div>
                )}

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Memo / Reference</label>
                    <textarea value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-4 py-3 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none resize-none h-24 placeholder-gray-900" placeholder="Type notes here..." />
                </div>

                <div className="pt-2">
                   <button type="submit" className="w-full flex items-center justify-center gap-3 py-4 bg-primary hover:bg-blue-600 text-white rounded-2xl font-bold transition-all shadow-xl shadow-blue-900/30 active:scale-[0.98] btn-float text-sm uppercase tracking-widest">
                      {mode === 'template' ? <Save size={20} /> : (initialData ? <Save size={20} /> : <Check size={20} />)}
                      {mode === 'template' ? 'Save Shortcut' : (initialData ? 'Commit Update' : 'Commit Entry')}
                  </button>
                </div>
            </form>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Receivable, Transaction, CurrencyCode, RecurrenceFrequency } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { format, isPast, addDays, addWeeks, addMonths, addYears, parseISO, endOfDay } from 'date-fns';
import { Plus, CheckCircle, ArrowUpRight, ArrowDownLeft, Repeat, Pencil, Trash2, HandCoins, FileText, Filter, Copy, RefreshCw, Users, Info } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { SearchableSelect } from '../components/ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';
import { InvoiceModal } from '../components/InvoiceModal';
import { useNavigate, useLocation } from 'react-router-dom';

type Mode = 'receivable' | 'payable';
type SubMode = 'invoice' | 'bill' | 'loan';

export const ApAr: React.FC = () => {
  const { state, dispatch } = useFinance();
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTab, setActiveTab] = useState<'all' | 'receivable' | 'payable'>('all');

  // Modals
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [invoiceData, setInvoiceData] = useState<Receivable | null>(null);

  // Selection
  const [selectedItem, setSelectedItem] = useState<Receivable | null>(null);

  // Form State
  const [formMode, setFormMode] = useState<Mode>('receivable');
  const [formSubMode, setFormSubMode] = useState<SubMode>('invoice');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [partyId, setPartyId] = useState('');
  const [targetAccountId, setTargetAccountId] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState<CurrencyCode>('QAR');

  // Fix: Use local YYYY-MM-DD for default to prevent "yesterday" bugs
  const getTodayLocal = () => {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };
  const [issueDate, setIssueDate] = useState('');
  const [dueDate, setDueDate] = useState('');

  const [notes, setNotes] = useState('');
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  // Payment State
  const [paymentAccountId, setPaymentAccountId] = useState('');
  const [paymentAmount, setPaymentAmount] = useState('');

  // Handle Navigation Shortcuts
  useEffect(() => {
      if (location.state) {
          const { openMode, openSubMode } = location.state as any;
          if (openMode && openSubMode) {
              handleOpenAdd(openMode, openSubMode);
              // Clear state to avoid reopening on refresh/back
              window.history.replaceState({}, document.title);
          }
      }
  }, [location]);

  // --- HELPERS ---

  const getPartyOptions = (mode: Mode) => {
    const type = mode === 'receivable' ? 'customer' : 'vendor';
    return state.parties.filter(p => p.type === type).map(p => ({ id: p.id, label: p.name }));
  };

  const getAccountOptions = (mode: Mode, subMode: SubMode) => {
    // Only allow Sub-Ledgers
    const subLedgers = state.accounts.filter(a => a.level === 'sub_ledger' && a.isPosting);

    if (mode === 'receivable') {
        if (subMode === 'loan') {
            // Money leaving Bank (Credit Asset)
            return subLedgers.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Revenue (Credit Revenue)
        return subLedgers.filter(a => a.class === 'Revenue').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    } else {
        if (subMode === 'loan') {
             // Money entering Bank (Debit Asset)
             return subLedgers.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Expense (Debit Expense)
        return subLedgers.filter(a => a.class === 'Expenses' || a.class === 'Liabilities').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    }
  };

  // Only allow Cash & Cash Equivalents (111xx)
  const cashGroup = state.accounts.find(a => a.code === '11100');
  const cashOptions = state.accounts
      .filter(a => 
          a.isPosting && 
          (
              a.code.startsWith('111') || 
              (cashGroup && a.parentId === cashGroup.id)
          )
      )
      .map(a => ({ id: a.id, label: a.name, subLabel: a.code }));

  // --- ACTIONS ---

  const goToPartySOA = (partyId: string) => {
      const party = state.parties.find(p => p.id === partyId);
      if (party?.linkedAccountId) {
          navigate('/reports', { state: { tab: 'soa', accountId: party.linkedAccountId } });
      } else {
          alert("This party is not linked to a specific sub-ledger account.");
      }
  };

  const handleOpenAdd = (mode: Mode, subMode: SubMode) => {
      resetForm();
      setFormMode(mode);
      setFormSubMode(subMode);

      // Auto-select bank for loans (if it is a sub ledger)
      if (subMode === 'loan') {
          const bank = state.accounts.find(c => c.class === 'Assets' && c.level === 'sub_ledger' && c.name.toLowerCase().includes('bank'));
          if (bank) setTargetAccountId(bank.id);
      }

      setIsFormOpen(true);
  };

  const handleOpenEdit = (item: Receivable) => {
      setEditingId(item.id);
      setFormMode(item.type);
      setFormSubMode(item.subType || (item.type === 'receivable' ? 'invoice' : 'bill'));
      setPartyId(item.partyId || '');
      setTargetAccountId(item.targetAccountId || '');
      setAmount((item.originalAmount || item.amount).toString());
      setCurrency(item.currency || 'QAR');
      setIssueDate(item.issueDate ? item.issueDate.split('T')[0] : getTodayLocal());
      setDueDate(item.dueDate.split('T')[0]);
      setNotes(item.notes || '');
      setIsRecurring(!!item.recurring?.active);
      setRecurFreq(item.recurring?.frequency || 'monthly');
      setIsFormOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
      e.preventDefault();
      const finalValStr = evaluateMathExpression(amount);
      const val = parseFloat(finalValStr);
      if (isNaN(val) || !partyId || !targetAccountId) {
          alert("Please fill all required fields correctly.");
          return;
      }

      const finalAmountQAR = currency === 'PHP' ? val / EXCHANGE_RATE_QAR_TO_PHP : val;
      const party = state.parties.find(p => p.id === partyId);
      const newId = editingId || Math.random().toString(36).substr(2, 9);

      const validIssueDate = issueDate ? new Date(issueDate).toISOString() : new Date().toISOString();

      const payload: Receivable = {
          id: newId,
          type: formMode,
          subType: formSubMode,
          partyId,
          partyName: party?.name || 'Unknown',
          targetAccountId,
          amount: finalAmountQAR,
          paidAmount: 0,
          originalAmount: val,
          currency,
          issueDate: validIssueDate,
          dueDate: new Date(dueDate).toISOString(),
          status: 'pending',
          notes,
          recurring: isRecurring ? { active: true, amount: val, frequency: recurFreq, nextDueDate: dueDate } : undefined
      };

      if (editingId) {
          // Preserve existing payments on edit
          const existing = state.receivables.find(r => r.id === editingId);
          payload.paidAmount = existing?.paidAmount || 0;
          if (payload.paidAmount >= payload.amount) payload.status = 'paid';
          dispatch({ type: 'UPDATE_RECEIVABLE', payload });
      } else {
          dispatch({ type: 'ADD_RECEIVABLE', payload });
          createAccrualTransaction(payload, newId);
      }
      setIsFormOpen(false);
  };

  const createAccrualTransaction = (item: Receivable, id: string) => {
      // Logic to create the underlying GL transaction
      const party = state.parties.find(p => p.id === item.partyId);
      const partyLinkedAccount = party?.linkedAccountId;

      if (!partyLinkedAccount) {
          console.warn("Party has no linked account for accrual posting.");
          return;
      }

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: item.issueDate || new Date().toISOString(), // Use provided issue date
          currency: item.currency,
          amount: item.amount,
          originalAmount: item.originalAmount,
          relatedPartyId: item.partyId,
          source: item.subType === 'loan' ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: `Accrual: ${item.subType} Ref:${id}`, 
          type: item.type === 'receivable' ? (item.subType === 'loan' ? 'transfer' : 'income') : (item.subType === 'loan' ? 'transfer' : 'expense'),

          accountId: item.type === 'receivable' 
            ? partyLinkedAccount // Dr Party AR
            : (item.subType === 'loan' ? item.targetAccountId : item.targetAccountId), // Dr Bank or Expense

          paymentAccountId: item.type === 'receivable'
            ? item.targetAccountId // Cr Revenue or Bank
            : partyLinkedAccount // Cr Party AP
      };

      dispatch({ type: 'ADD_TRANSACTION', payload: tx });
  };

  const handleSync = () => {
      const confirmSync = confirm("Reconcile Transactions?\n\nThis will scan all active Payables/Receivables and create missing GL transactions if they were accidentally deleted.");
      if (!confirmSync) return;

      let createdCount = 0;
      state.receivables.forEach(r => {
          const exists = state.transactions.some(t => t.note?.includes(`Ref:${r.id}`));
          if (!exists) {
              createAccrualTransaction(r, r.id);
              createdCount++;
          }
      });

      alert(createdCount > 0 ? `Synced! Created ${createdCount} missing transactions.` : "All records are in sync.");
  };

  const handleDelete = (id: string) => {
      if(confirm("Delete this record? Associated Journal Entries will be removed.")) {
          dispatch({ type: 'DELETE_RECEIVABLE', payload: id });
      }
  };

  const handleOpenPayment = (item: Receivable) => {
      setSelectedItem(item);
      const bank = cashOptions.find(c => c.label.toLowerCase().includes('bank')) || cashOptions[0];
      setPaymentAccountId(bank ? bank.id : '');

      // Default to remaining balance
      const remaining = item.amount - (item.paidAmount || 0);
      setPaymentAmount(remaining.toString());

      setIsPaymentModalOpen(true);
  };

  const handleProcessPayment = (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedItem || !paymentAccountId) return;

      const payValStr = evaluateMathExpression(paymentAmount);
      const payVal = parseFloat(payValStr);
      if (isNaN(payVal) || payVal <= 0) {
          alert("Please enter a valid amount.");
          return;
      }

      const item = selectedItem;
      const currentPaid = item.paidAmount || 0;
      const newPaidTotal = currentPaid + payVal;
      const isFullyPaid = newPaidTotal >= (item.amount - 0.01); // Tolerance for float math

      // Update Receivable Record
      const updatedItem: Receivable = {
          ...item,
          paidAmount: newPaidTotal,
          status: isFullyPaid ? 'paid' : 'pending',
          paidDate: isFullyPaid ? new Date().toISOString() : undefined
      };
      dispatch({ type: 'UPDATE_RECEIVABLE', payload: updatedItem });

      // Create Payment Transaction (Partial Amount)
      const party = state.parties.find(p => p.id === item.partyId);
      const partyLinkedAccount = party?.linkedAccountId;

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          currency: item.currency,
          amount: payVal, // Use partial amount for GL
          originalAmount: payVal, // Assuming same currency base for simplicity or 1:1 if QAR
          relatedPartyId: item.partyId,
          source: item.subType === 'loan' ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: `Settlement (${isFullyPaid ? 'Full' : 'Partial'}): ${item.subType} Ref:${item.id}`,
          type: item.type === 'receivable' ? 'income' : 'expense',
          accountId: item.type === 'receivable' ? paymentAccountId : (partyLinkedAccount || ''),
          paymentAccountId: item.type === 'receivable' ? (partyLinkedAccount || '') : paymentAccountId
      };

      if (partyLinkedAccount) {
         dispatch({ type: 'ADD_TRANSACTION', payload: tx });
      }

      // Handle Recurring - ONLY if Fully Paid (or if user wants auto-recurrence on settlement)
      // Logic: Only generate next item if we are fully setting the current one.
      if (isFullyPaid && item.recurring?.active) {
          const freq = item.recurring.frequency;

          const dueStr = item.dueDate.split('T')[0];
          const baseDueDate = new Date(dueStr + 'T00:00:00.000Z');
          let nextDueDate = baseDueDate;

          if (freq === 'daily') nextDueDate = addDays(baseDueDate, 1);
          if (freq === 'weekly') nextDueDate = addWeeks(baseDueDate, 1);
          if (freq === 'monthly') nextDueDate = addMonths(baseDueDate, 1);
          if (freq === 'yearly') nextDueDate = addYears(baseDueDate, 1);

          const issueStr = item.issueDate ? item.issueDate.split('T')[0] : dueStr;
          const baseIssueDate = new Date(issueStr + 'T00:00:00.000Z');
          let nextIssueDate = baseIssueDate;

          if (freq === 'daily') nextIssueDate = addDays(baseIssueDate, 1);
          if (freq === 'weekly') nextIssueDate = addWeeks(baseIssueDate, 1);
          if (freq === 'monthly') nextIssueDate = addMonths(baseIssueDate, 1);
          if (freq === 'yearly') nextIssueDate = addYears(baseIssueDate, 1);

          const nextId = Math.random().toString(36).substr(2, 9);
          const nextItem: Receivable = {
              ...item,
              id: nextId,
              dueDate: nextDueDate.toISOString(),
              status: 'pending',
              paidDate: undefined,
              paidAmount: 0,
              issueDate: nextIssueDate.toISOString() 
          };
          dispatch({ type: 'ADD_RECEIVABLE', payload: nextItem });

          if (item.subType === 'invoice' || item.subType === 'bill') {
              const txType = item.type === 'receivable' ? 'income' : 'expense';
              const nextAccrualTx: Transaction = {
                  id: Math.random().toString(36).substr(2, 9),
                  date: nextIssueDate.toISOString(), 
                  currency: item.currency,
                  amount: item.amount,
                  originalAmount: item.originalAmount,
                  relatedPartyId: item.partyId,
                  source: 'side_hustle',
                  note: `Accrual (Auto): ${item.subType} Ref:${nextId}`,
                  type: txType,
                  accountId: item.type === 'receivable' ? (partyLinkedAccount || '') : item.targetAccountId,
                  paymentAccountId: item.type === 'receivable' ? item.targetAccountId : (partyLinkedAccount || '')
              };
              if (partyLinkedAccount) {
                  dispatch({ type: 'ADD_TRANSACTION', payload: nextAccrualTx });
              }
          }
      }

      setIsPaymentModalOpen(false);
  };

  const resetForm = () => {
      setEditingId(null); setPartyId(''); setTargetAccountId(''); setAmount(''); setNotes(''); setIsRecurring(false); 
      setIssueDate(getTodayLocal());
      setDueDate('');
  };

  // --- RENDER ---
  const filteredList = state.receivables.filter(item => {
      if (item.status === 'paid') return false; 
      if (activeTab === 'all') return true;
      return item.type === activeTab;
  }).sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  const todayEnd = endOfDay(new Date());

  const totalAr = state.receivables.filter(r => 
      r.type === 'receivable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= todayEnd)
  ).reduce((s, r) => s + (r.amount - (r.paidAmount || 0)), 0);

  const totalAp = state.receivables.filter(r => 
      r.type === 'payable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= todayEnd)
  ).reduce((s, r) => s + (r.amount - (r.paidAmount || 0)), 0);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* Header & Tabs - Unchanged */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div><h1 className="text-3xl font-bold text-gray-100 tracking-tight">AP / AR</h1><p className="text-gray-400 text-sm">Manage invoices, bills, and loans</p></div>
            <div className="flex gap-2 flex-wrap">
