                            </div>
                        </div>
                    </div>
                )}
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { TransactionType, SourceType, Transaction, CurrencyCode, RecurrenceFrequency, RecurringTransaction, TransactionTemplate } from '../types';
import { CURRENCIES } from '../constants';
import { Check, ArrowRightLeft, LayoutGrid, List, Save, ArrowRight, Repeat, Star, Tag } from 'lucide-react';
import { addDays, addMonths, addWeeks, addYears } from 'date-fns';
import { SearchableSelect } from './ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';
import { useNavigate } from 'react-router-dom';

interface TransactionFormProps {
  onComplete: () => void;
  initialType?: TransactionType;
  initialData?: Transaction | null;
  mode?: 'transaction' | 'template';
  onSaveTemplate?: (template: TransactionTemplate) => void;
  initialTemplate?: TransactionTemplate | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ 
    onComplete, 
    initialType = 'expense', 
    initialData, 
    mode = 'transaction',
    onSaveTemplate,
    initialTemplate
}) => {
  const { state, dispatch } = useFinance();
  const navigate = useNavigate();
  const baseCurrency = state.businessProfile.baseCurrency || 'USD';

  // Helper for Local YYYY-MM-DD
  const getTodayLocal = () => {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  // Template specific state
  const [templateName, setTemplateName] = useState(initialTemplate?.name || '');
  const [templateIcon, setTemplateIcon] = useState(initialTemplate?.icon || '⚡');

  // Shared state
  const [type, setType] = useState<TransactionType>(initialData?.type || initialType);
  const [amount, setAmount] = useState(
      initialData ? (initialData.originalAmount || initialData.amount).toString() : 
      (initialTemplate ? (initialTemplate.amount || '').toString() : '')
  );

  // Default currency to Base Currency if not provided
  const [currency, setCurrency] = useState<CurrencyCode>(initialData?.currency || initialTemplate?.currency || baseCurrency);

  const [accountId, setAccountId] = useState(initialData?.accountId || initialTemplate?.accountId || '');
  const [source, setSource] = useState<SourceType>(initialData?.source || initialTemplate?.source || 'personal');
  const [paymentAccountId, setPaymentAccountId] = useState(initialData?.paymentAccountId || initialTemplate?.paymentAccountId || '');
  // Fix: Use local date for default to avoid timezone shift errors
  const [date, setDate] = useState(initialData ? initialData.date.split('T')[0] : getTodayLocal());
  const [note, setNote] = useState(initialData?.note || initialTemplate?.note || '');
  const [partyId, setPartyId] = useState(initialData?.relatedPartyId || initialTemplate?.partyId || '');

  // Recurrence State (Transaction Mode Only)
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  const [viewMode, setViewMode] = useState<'form' | 'pos'>('pos');

  useEffect(() => {
    if (initialData || initialTemplate || mode === 'template') {
        setViewMode('form');

        // Infer Type from Account Class for Templates if not explicit
        if (mode === 'template' && accountId) {
             const acc = state.accounts.find(a => a.id === accountId);
             if (acc) {
                 if (acc.class === 'Revenue' || acc.class === 'Equity') setType('income');
                 else if (acc.class === 'Expenses' || acc.class === 'Liabilities') setType('expense');
             }
        }

        // Logic to swap UI fields for Income if editing existing data
        if (initialData && initialData.type === 'income' && !state.accounts.find(a => a.id === initialData.accountId)?.class.includes('Revenue')) {
             setAccountId(initialData.paymentAccountId || '');
             setPaymentAccountId(initialData.accountId);
        }
    } else {
        const isMobile = window.innerWidth < 768;
        if(isMobile) setViewMode('pos');
    }
  }, [initialData, initialTemplate, state.accounts, mode]);

  // AUTO-SET DEFAULT PAYMENT ACCOUNT
  useEffect(() => {
      if (initialData || initialTemplate) return; 
      // Only auto-select if it's a Sub-Ledger. 
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank') && c.level === 'sub_ledger');
      const cash = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('cash') && c.level === 'sub_ledger');

      if (type === 'expense') {
          if (bank) setPaymentAccountId(bank.id);
      } else if (type === 'income') {
          if (cash) setPaymentAccountId(cash.id);
      } else if (type === 'transfer') {
          if (bank) setPaymentAccountId(bank.id);
      }
  }, [type, state.accounts, initialData, initialTemplate]);

  // DATA TRANSFORMATION FOR SEARCHABLE SELECT
  const availableAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // Removed strict sub_ledger check to allow GL accounts (like default Bank/Cash) to be selected
          // if (c.level !== 'sub_ledger') return false; 

          if (type === 'transfer') return true; 

          if (type === 'expense') return c.class === 'Expenses' || c.class === 'Liabilities' || c.class === 'Assets'; 
          if (type === 'income') return c.class === 'Revenue' || c.class === 'Equity';

          return true;
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  const availableParties = state.parties
      .filter(e => e.type === (type === 'income' ? 'customer' : 'vendor'))
      .map(e => ({ id: e.id, label: e.name }));

  const transferSourceAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // Removed strict sub_ledger check
          // if (c.level !== 'sub_ledger') return false;

          if (type === 'transfer') return true;
          return c.class === 'Assets'; 
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  // Organize Currencies: Base Currency first, then others
  const sortedCurrencies = [...CURRENCIES].sort((a, b) => {
      if (a.code === baseCurrency) return -1;
      if (b.code === baseCurrency) return 1;
      return a.code.localeCompare(b.code);
  });

  const selectedCurrencySymbol = CURRENCIES.find(c => c.code === currency)?.symbol || '$';

  const handleAccountChange = (id: string) => {
    setAccountId(id);
  };

  const handleTemplateClick = (templateId: string) => {
      const t = state.templates.find(temp => temp.id === templateId);
      if(!t) return;

      const acc = state.accounts.find(c => c.id === t.accountId);
      if(acc) {
        const targetType = (acc.class === 'Assets' || acc.class === 'Liabilities') ? 'expense' : (acc.class === 'Revenue' ? 'income' : 'expense');
        setType(targetType as TransactionType);
        setAccountId(acc.id);
        if (t.source) setSource(t.source);
      }

      if(t.amount) setAmount(t.amount.toString());
      setCurrency(t.currency);
      if(t.note) setNote(t.note);
      if(t.partyId) setPartyId(t.partyId);
      if(t.paymentAccountId) setPaymentAccountId(t.paymentAccountId);

      setViewMode('form'); 
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);

    if (!finalAmountStr && mode === 'transaction') return; // Amount mandatory for transaction
    if (!accountId) { alert('Please select a main category/account.'); return; }

    if (type === 'transfer' && !paymentAccountId) {
        alert("Please select a 'From' account.");
        return;
    }
    if (type === 'transfer' && accountId === paymentAccountId) {
        alert("From and To accounts cannot be the same.");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr) || 0;

    // NOTE: In a real multi-currency system, we would ask for exchange rate if Currency != BaseCurrency.
    // For now, we assume direct entry relative to Base Currency or user handles conversion logic via input expression.
    // However, to respect the "Base Amount" field, if currency matches base, it's 1:1.
    // If different, we ideally prompt. For this specific implementation scope, we treat input amount as raw
    // and store it. The `amount` field in DB is meant to be Normalized.
    // We will just store inputAmount as amount for now unless we add an exchange rate picker.
    // Since the prompt emphasizes "Data Integrity", storing accurate original_amount is key.

    const finalAmountBase = inputAmount; // Simplified: Assuming user enters base equivalent or 1:1 for now

    // --- CRITICAL ACCOUNTING LOGIC ---
    let finalDebitAccount = accountId;
    let finalCreditAccount = paymentAccountId;

    if (type === 'income') {
        finalDebitAccount = paymentAccountId; // Bank becomes Dr
        finalCreditAccount = accountId;      // Revenue becomes Cr
    } 

    // --- TEMPLATE SAVE MODE ---
    if (mode === 'template') {
        if (!templateName) { alert('Please name your shortcut.'); return; }
        const templateData: TransactionTemplate = {
            id: initialTemplate?.id || Math.random().toString(36).substr(2, 9),
            name: templateName,
            icon: templateIcon,
            accountId: accountId, // Store the user selected account ID (Category), not the resolved debit/credit
            amount: inputAmount || undefined, // Optional in template
            currency: currency,
            note: note,
            partyId: partyId || undefined,
            paymentAccountId: paymentAccountId || undefined,
            source: source
        };
        if (onSaveTemplate) onSaveTemplate(templateData);
        onComplete();
        return;
    }

    // --- TRANSACTION SAVE MODE ---
    if (isNaN(inputAmount) || inputAmount <= 0) {
        alert("Invalid amount");
        return;
    }

    const transactionData: Transaction = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      date: new Date(date).toISOString(),
      type,
      amount: finalAmountBase, // This should technically be the converted amount to base
      originalAmount: inputAmount,
      currency: currency,
      accountId: finalDebitAccount, // DEBIT
      source,
      paymentAccountId: finalCreditAccount || undefined, // CREDIT
      note,
      relatedPartyId: partyId || undefined
    };

    if (initialData) {
        dispatch({ type: 'UPDATE_TRANSACTION', payload: transactionData });
    } else {
        dispatch({ type: 'ADD_TRANSACTION', payload: transactionData });

        if (isRecurring) {
            // STRICT DATE CALCULATION
            const baseDate = new Date(date + 'T00:00:00.000Z');
            let nextDate = baseDate;

            if (recurFreq === 'daily') nextDate = addDays(baseDate, 1);
            if (recurFreq === 'weekly') nextDate = addWeeks(baseDate, 1);
            if (recurFreq === 'monthly') nextDate = addMonths(baseDate, 1);
            if (recurFreq === 'yearly') nextDate = addYears(baseDate, 1);

            const recurringRule: RecurringTransaction = {
                id: Math.random().toString(36).substr(2, 9),
                active: true,
                type,
                accountId: finalDebitAccount,
                amount: finalAmountBase,
                originalAmount: inputAmount,
                currency,
                source,
                paymentAccountId: finalCreditAccount || undefined,
                partyId: partyId || undefined,
                note: note,
                frequency: recurFreq,
                nextDueDate: nextDate.toISOString()
            };

            dispatch({ type: 'ADD_RECURRING', payload: recurringRule });
            // Use local string for alert to be friendly
            alert(`Recurring rule created. Next due: ${nextDate.toISOString().split('T')[0]}`);
        }
    }
    onComplete();
  };

  return (
    <div className="space-y-4">
        {!initialData && mode === 'transaction' && (
            <div className="flex justify-end mb-2">
                <button 
                    onClick={() => setViewMode(viewMode === 'form' ? 'pos' : 'form')}
                    className="text-xs flex items-center gap-1.5 text-primary hover:text-blue-400 font-bold px-4 py-2.5 bg-gray-800 rounded-xl border border-gray-700 glass-card btn-float active:scale-95"
                >
                    {viewMode === 'form' ? <><LayoutGrid size={16} /> Use Shortcuts</> : <><List size={16} /> Manual Entry</>}
                </button>
            </div>
        )}

        {viewMode === 'pos' && !initialData && mode === 'transaction' ? (
            <div className="grid grid-cols-2 gap-3 max-h-[60vh] overflow-y-auto no-scrollbar pb-4">
                {state.templates.length === 0 && (
                    <div className="col-span-2 text-center py-12 text-gray-500 text-sm border border-dashed border-gray-700 rounded-2xl flex flex-col items-center gap-3">
                        <LayoutGrid size={32} className="opacity-20" />
                        <div>No shortcuts configured.<br/>Add them in Settings.</div>
                    </div>
                )}
                {state.templates.map(t => {
                    const tSym = CURRENCIES.find(c => c.code === t.currency)?.symbol || '$';
                    return (
                        <button
                            key={t.id}
                            onClick={() => handleTemplateClick(t.id)}
                            className="flex flex-col items-center justify-center p-5 bg-gray-800/60 backdrop-blur-md border border-gray-700 hover:border-primary hover:bg-gray-800/80 rounded-2xl transition-all active:scale-95 btn-float group"
                        >
                            <span className="text-4xl mb-3 group-hover:scale-110 transition-transform">{t.icon || '⚡'}</span>
                            <span className="text-sm font-bold text-gray-100 tracking-tight">{t.name}</span>
                            {t.amount && (
                            <span className="text-[10px] text-gold-500/80 font-mono mt-1 px-1.5 py-0.5 bg-gold-500/5 rounded border border-gold-500/10">
                                {tSym}{t.amount.toLocaleString()}
                            </span>
                            )}
                        </button>
                    );
                })}
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="space-y-5 animate-fade-in">

                {/* QUICK SHORTCUTS FOR ACCRUALS */}
                {mode === 'transaction' && !initialData && (
                    <div className="grid grid-cols-3 gap-3 mb-2">
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'receivable', openSubMode: 'invoice' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-emerald-500/10 to-teal-600/10 hover:from-emerald-500/30 hover:to-teal-600/30 border border-emerald-500/20 hover:border-emerald-500/50 text-emerald-400 transition-all active:scale-95 shadow-lg shadow-emerald-900/5 backdrop-blur-md"
                        >
                            AR
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'payable', openSubMode: 'bill' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-red-500/10 to-orange-600/10 hover:from-red-500/30 hover:to-orange-600/30 border border-red-500/20 hover:border-red-500/50 text-red-400 transition-all active:scale-95 shadow-lg shadow-red-900/5 backdrop-blur-md"
                        >
                            AP
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'receivable', openSubMode: 'loan' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-purple-500/10 to-indigo-600/10 hover:from-purple-500/30 hover:to-indigo-600/30 border border-purple-500/20 hover:border-purple-500/50 text-purple-400 transition-all active:scale-95 shadow-lg shadow-purple-900/5 backdrop-blur-md"
                        >
                            P
                        </button>
                    </div>
                )}

                {/* TEMPLATE HEADER FIELDS */}
                {mode === 'template' && (
                    <div className="bg-indigo-900/20 p-4 rounded-xl border border-indigo-500/30 space-y-4 mb-2">
                        <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                            <Star size={14} /> Shortcut Details
                        </h4>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Shortcut Name</label>
                            <input 
                                type="text" 
                                value={templateName} 
                                onChange={e => setTemplateName(e.target.value)} 
                                className="w-full px-4 py-2.5 bg-gray-950 text-white border border-gray-700 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                                placeholder="e.g. Morning Coffee"
                                autoFocus
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Icon / Emoji</label>
                            <div className="flex gap-2">
                                {['⚡','☕','⛽','🛒','🍔','🚗','🏠','💊','✈️','🎓'].map(icon => (
                                    <button 
                                        type="button" 
                                        key={icon} 
                                        onClick={() => setTemplateIcon(icon)}
                                        className={`w-10 h-10 rounded-lg flex items-center justify-center text-xl transition-colors ${templateIcon === icon ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                                    >
                                        {icon}
                                    </button>
                                ))}
                                <input 
                                    type="text" 
                                    value={templateIcon} 
                                    onChange={e => setTemplateIcon(e.target.value)} 
                                    className="w-12 h-10 text-center bg-gray-950 border border-gray-700 rounded-lg text-white" 
                                    placeholder="?"
                                />
                            </div>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-3 gap-2 p-1.5 bg-gray-900/50 rounded-2xl border border-gray-700">
                    <button type="button" onClick={() => { setType('expense'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'expense' ? 'bg-gray-700 text-red-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Expense</button>
                    <button type="button" onClick={() => { setType('income'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'income' ? 'bg-gray-700 text-emerald-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Income</button>
                    <button type="button" onClick={() => { setType('transfer'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'transfer' ? 'bg-gray-700 text-blue-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Transfer</button>
                </div>

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Amount {mode === 'template' && '(Optional)'}</label>
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gold-500 text-xl font-bold">{selectedCurrencySymbol}</span>
                        <input 
                            type="text" 
                            inputMode="decimal"
                            value={amount} 
                            onChange={(e) => setAmount(e.target.value)} 
                            onBlur={handleAmountBlur}
                            className="w-full pl-12 pr-4 py-4 text-3xl font-bold text-white bg-gray-950 border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary focus:border-transparent outline-none placeholder-gray-800" 
                            placeholder={mode === 'template' ? "0.00 (Optional)" : "0.00"}
                            required={mode === 'transaction'}
                        />
                        </div>
                        <div className="w-24">
                            <select 
                                value={currency} 
                                onChange={(e) => setCurrency(e.target.value as CurrencyCode)} 
                                className="w-full h-full px-2 bg-gray-950 text-white border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary outline-none font-bold text-center appearance-none"
                            >
                                {sortedCurrencies.map(c => (
                                    <option key={c.code} value={c.code}>{c.code}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>

                {type === 'transfer' ? (
                     <div className="grid grid-cols-1 gap-5 p-5 bg-blue-900/10 border border-blue-500/20 rounded-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-3 opacity-5">
                          <ArrowRightLeft size={64} className="text-blue-500" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">From Account (Credit)</label>
                            <SearchableSelect
                                options={transferSourceAccounts}
                                value={paymentAccountId}
                                onChange={setPaymentAccountId}
                                placeholder="Select Source..."
                                required
                            />
                        </div>
                        <div className="flex justify-center -my-3 relative z-10">
                            <div className="bg-gray-900 border border-blue-500/30 p-2 rounded-full shadow-lg">
                              <ArrowRight className="text-blue-500 rotate-90" size={16} />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">To Account (Debit)</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Destination..."
                                required
                            />
                        </div>
                     </div>
                ) : (
                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Classification ({type === 'income' ? 'Revenue' : 'Expense'})</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Account..."
                                required
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Payment via</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'None'}, ...transferSourceAccounts]}
                                    value={paymentAccountId}
                                    onChange={setPaymentAccountId}
                                    placeholder="Source..."
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1 truncate">{type === 'income' ? 'Payer' : 'Merchant'}</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'Opt...'}, ...availableParties]}
                                    value={partyId}
                                    onChange={setPartyId}
                                    placeholder="Party..."
                                />
                            </div>
                        </div>
                    </div>
                )}

                {mode === 'transaction' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Effective Date</label>
                            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3.5 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none" />
                        </div>
                    </div>
                )}

                {!initialData && mode === 'transaction' && (
                    <div className="p-4 bg-gray-950/50 rounded-2xl border border-gray-800">
                        <div className="flex items-center gap-3 mb-2">
                            <input 
                                type="checkbox" 
                                id="isRecurring"
                                checked={isRecurring} 
                                onChange={e => setIsRecurring(e.target.checked)} 
                                className="w-5 h-5 rounded-lg bg-gray-900 border-gray-700 focus:ring-primary text-primary" 
                            />
                            <label htmlFor="isRecurring" className="text-sm font-bold text-gray-300 flex items-center gap-2 cursor-pointer">
                                <Repeat size={14} className="text-gold-500" />
                                Automate Transaction?
                            </label>
                        </div>
                        {isRecurring && (
                            <div className="flex items-center gap-3 animate-fade-in pl-8 mt-2">
                                <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">Interval:</span>
                                <select 
                                    className="px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white text-xs outline-none focus:border-gold-500 font-bold uppercase" 
                                    value={recurFreq} 
                                    onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)}
                                >
                                    <option value="daily">Daily</option>
                                    <option value="weekly">Weekly</option>
                                    <option value="monthly">Monthly</option>
                                    <option value="yearly">Yearly</option>
                                </select>
                            </div>
                        )}
                    </div>
                )}

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Memo / Reference</label>
                    <textarea value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-4 py-3 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none resize-none h-24 placeholder-gray-900" placeholder="Type notes here..." />
                </div>

                <div className="pt-2">
                   <button type="submit" className="w-full flex items-center justify-center gap-3 py-4 bg-primary hover:bg-blue-600 text-white rounded-2xl font-bold transition-all shadow-xl shadow-blue-900/30 active:scale-[0.98] btn-float text-sm uppercase tracking-widest">
                      {mode === 'template' ? <Save size={20} /> : (initialData ? <Save size={20} /> : <Check size={20} />)}
                      {mode === 'template' ? 'Save Shortcut' : (initialData ? 'Commit Update' : 'Commit Entry')}
                  </button>
                </div>
            </form>
        )}
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Trash2, Plus, LayoutGrid, Book, AlertTriangle, Users, Pencil, Check, X, Database, Search, FileJson, FileSpreadsheet, Building2, ChevronRight, ChevronDown, Folder, Repeat, Mail, Phone, MapPin, Tag, Star, Upload, FileText, Globe, ArrowRightLeft } from 'lucide-react';
import { Account, TransactionTemplate, AccountClass, Party, PartyType, AccountLevel, Transaction, AppState, CurrencyCode } from '../types';
import { Modal } from '../components/ui/Modal';
import { format, parseISO, addMonths, addWeeks, addYears, addDays, endOfDay } from 'date-fns';
import { excelService } from '../services/excel';
import { buildAccountTree, AccountNode } from '../utils/accountHierarchy';
import { TransactionForm } from '../components/TransactionForm';
import { useNavigate, useLocation } from 'react-router-dom';
import { CURRENCIES } from '../constants';

type Tab = 'profile' | 'coa' | 'parties' | 'recurring' | 'templates' | 'migration' | 'danger';

export const Settings: React.FC = () => {
  const { state, dispatch } = useFinance();
  const navigate = useNavigate();
  const location = useLocation();
  const baseCurrency = state.businessProfile.baseCurrency || 'USD';

  // Default to COA as requested
  const [activeTab, setActiveTab] = useState<Tab>('coa');

  // Handle tab switching via navigation state
  useEffect(() => {
      if (location.state && location.state.tab) {
          setActiveTab(location.state.tab as Tab);
      }
  }, [location]);

  // Profile State
  const [bizName, setBizName] = useState(state.businessProfile.name);
  const [bizAddress, setBizAddress] = useState(state.businessProfile.address);
  const [bizPhone, setBizPhone] = useState(state.businessProfile.phone);
  const [bizEmail, setBizEmail] = useState(state.businessProfile.email);
  const [bizFooter, setBizFooter] = useState(state.businessProfile.footerNote || '');

  // COA State
  const [coaSearch, setCoaSearch] = useState('');
  const [expandedNodes, setExpandedNodes] = useState<Record<string, boolean>>({});
  const [newAccName, setNewAccName] = useState('');
  const [newAccClass, setNewAccClass] = useState<AccountClass>('Expenses');
  const [newAccCode, setNewAccCode] = useState('');
  const [newAccParent, setNewAccParent] = useState('');
  const [newAccLevel, setNewAccLevel] = useState<AccountLevel>('gl');
  const [editingAccId, setEditingAccId] = useState<string | null>(null);
  const [editingAccName, setEditingAccName] = useState('');

  // Parties State
  const [partySearch, setPartySearch] = useState('');
  const [partyName, setPartyName] = useState('');
  const [partyType, setPartyType] = useState<PartyType>('vendor');
  const [partyPhone, setPartyPhone] = useState('');
  const [partyEmail, setPartyEmail] = useState('');

  // Template Modal State
  const [isTemplateModalOpen, setIsTemplateModalOpen] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState<TransactionTemplate | null>(null);

  // Migration State
  const [migrationTarget, setMigrationTarget] = useState<CurrencyCode | ''>('');
  const [migrationRate, setMigrationRate] = useState('');
  const [migrationConfirm, setMigrationConfirm] = useState('');

  // Refs
  const backupInputRef = useRef<HTMLInputElement>(null);
  const excelInputRef = useRef<HTMLInputElement>(null);

  // --- HIERARCHY LOGIC ---
  const accountTree = useMemo(() => {
      const todayEnd = endOfDay(new Date());
      const effectiveTransactions = state.transactions.filter(t => parseISO(t.date) <= todayEnd);
      return buildAccountTree(state.accounts, effectiveTransactions);
  }, [state.accounts, state.transactions]);

  const toggleNode = (id: string) => {
      setExpandedNodes(prev => ({ ...prev, [id]: !prev[id] }));
  };

  useMemo(() => {
      if (coaSearch) {
          const allIds: Record<string, boolean> = {};
          state.accounts.forEach(a => allIds[a.id] = true);
          setExpandedNodes(allIds);
      }
  }, [coaSearch, state.accounts]);

  const flatAccounts = useMemo(() => state.accounts.filter(a => a.level === 'group' || a.level === 'class' || a.level === 'gl').sort((a,b) => a.code.localeCompare(b.code)), [state.accounts]);

  // Update Class when Parent changes
  useEffect(() => {
      if (newAccParent) {
          const parent = state.accounts.find(a => a.id === newAccParent);
          if (parent) {
              setNewAccClass(parent.class);
          }
      }
  }, [newAccParent, state.accounts]);

  // --- HANDLERS ---

  const handleSaveProfile = (e: React.FormEvent) => { 
      e.preventDefault(); 
      dispatch({ type: 'UPDATE_BUSINESS_PROFILE', payload: { ...state.businessProfile, name: bizName, address: bizAddress, phone: bizPhone, email: bizEmail, footerNote: bizFooter } }); 
      alert('Profile Saved'); 
  };

  const handleMigration = (e: React.FormEvent) => {
    e.preventDefault();
    if (migrationConfirm !== 'CONFIRM') {
        alert("Please type CONFIRM to execute migration.");
        return;
    }
    const rate = parseFloat(migrationRate);
    if (!migrationTarget || isNaN(rate) || rate <= 0) {
        alert("Invalid target currency or rate.");
        return;
    }

    if (confirm(`WARNING: This will permanently multiply ALL historical amounts by ${rate} and change base currency to ${migrationTarget}. This cannot be undone. Proceed?`)) {
        dispatch({ 
            type: 'MIGRATE_BASE_CURRENCY', 
            payload: { newCurrency: migrationTarget, rate: rate } 
        });
        alert("Migration Complete. The dashboard will now reflect the new currency.");
        setMigrationTarget('');
        setMigrationRate('');
        setMigrationConfirm('');
        setActiveTab('profile'); // Switch away
    }
  };

  const handleAddAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAccName || !newAccCode) return;
    let normalBalance: 'debit' | 'credit' = 'debit';
    if (['Liabilities', 'Equity', 'Revenue'].includes(newAccClass)) normalBalance = 'credit';

    dispatch({ type: 'ADD_ACCOUNT', payload: {
        id: Math.random().toString(36).substr(2, 9),
        name: newAccName,
        class: newAccClass,
        code: newAccCode,
        level: newAccLevel,
        parentId: newAccParent || undefined,
        normalBalance,
        isPosting: newAccLevel === 'gl' || newAccLevel === 'sub_ledger'
    }});
    setNewAccName(''); setNewAccCode('');
  };

  const handleAddParty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!partyName) return;
    let targetParentCode = '11900'; 
    let targetClass: AccountClass = 'Assets';
    let targetNormalBalance: 'debit' | 'credit' = 'debit';
    const parentAccount = state.accounts.find(a => a.code === targetParentCode);

    if (!parentAccount) {
        alert(`System Error: Parent GL Account ${targetParentCode} (Parties) not found.`);
        return;
    }

    const siblings = state.accounts.filter(a => a.parentId === parentAccount.id);
    const partyAccountCode = `${parentAccount.code}.${siblings.length + 1}`;
    const partyAccountId = Math.random().toString(36).substr(2, 9);

    const partyAccount: Account = {
        id: partyAccountId,
        code: partyAccountCode,
        name: partyName,
        class: targetClass,
        level: 'sub_ledger',
        parentId: parentAccount.id,
        normalBalance: targetNormalBalance,
        isPosting: true
    };
    dispatch({ type: 'ADD_ACCOUNT', payload: partyAccount });

    const newParty: Party = {
        id: Math.random().toString(36).substr(2, 9),
        name: partyName,
        type: partyType,
        phone: partyPhone,
        email: partyEmail,
        linkedAccountId: partyAccountId
    };
    dispatch({ type: 'ADD_PARTY', payload: newParty });

    setPartyName(''); setPartyPhone(''); setPartyEmail('');
    alert(`Party created.`);
  };

  const handleSaveTemplate = (template: TransactionTemplate) => {
      if (editingTemplate) {
          dispatch({ type: 'DELETE_TEMPLATE', payload: editingTemplate.id });
      }
      dispatch({ type: 'ADD_TEMPLATE', payload: template });
      setIsTemplateModalOpen(false);
      setEditingTemplate(null);
  };

  const handleDelete = (type: string, id: string) => { 
      if (confirm('Are you sure? This action cannot be undone.')) { 
          if(type === 'ACCOUNT') dispatch({ type: 'DELETE_ACCOUNT', payload: id }); 
          if(type === 'TEMPLATE') dispatch({ type: 'DELETE_TEMPLATE', payload: id }); 
          if(type === 'PARTY') dispatch({ type: 'DELETE_PARTY', payload: id }); 
          if(type === 'RECURRING') dispatch({ type: 'DELETE_RECURRING', payload: id }); 
      } 
  };

  const goToSOA = (accountId: string) => {
      navigate('/reports', { state: { tab: 'soa', accountId } });
  };

  const handleBackup = () => { const dataStr = JSON.stringify(state, null, 2); const link = document.createElement('a'); link.href = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr); link.download = `backup_${format(new Date(), 'yyyy-MM-dd')}.json`; link.click(); };
  const handleExcelExport = () => excelService.exportDataToExcel(state);
  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if(!file)return; const reader=new FileReader(); reader.onload=async(ev)=>{ try{ const json=JSON.parse(ev.target?.result as string); if(confirm("Restore?")) dispatch({type:'SET_STATE', payload:json}); }catch(err){alert("Invalid JSON");}}; reader.readAsText(file); };
  const handleExcelImport = async (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if(!file)return; if(confirm("Overwrite data?")) { try{ const data=await excelService.importDataFromExcel(file); if(data.transactions) dispatch({type:'SET_STATE', payload:{...state, ...data}}); alert("Imported"); }catch(e){alert("Error");}} };
  const startEditingAcc = (acc: Account) => { setEditingAccId(acc.id); setEditingAccName(acc.name); };
  const saveEditingAcc = () => { if(editingAccId) { const orig = state.accounts.find(c => c.id === editingAccId); if(orig) dispatch({ type: 'UPDATE_ACCOUNT', payload: { ...orig, name: editingAccName } }); setEditingAccId(null); } };
  const cancelEditingAcc = () => { setEditingAccId(null); };
  const handleReset = () => { if(confirm('RESET DATA? ALL TRANSACTIONS WILL BE LOST.')) dispatch({ type: 'RESET_DATA' }); };

  const getBalanceColor = (node: AccountNode) => {
    const bal = node.totalBalance;
    if (Math.abs(bal) < 0.01) return 'text-gray-500';
    if (['Liabilities', 'Equity', 'Revenue'].includes(node.class)) {
        return bal < 0 ? 'text-emerald-400' : 'text-red-400';
    }
    return bal > 0 ? 'text-emerald-400' : 'text-red-400';
  };

  const renderTreeNodes = (nodes: AccountNode[], depth: number = 0) => {
      return nodes.map(node => {
          if (coaSearch) {
              const match = node.name.toLowerCase().includes(coaSearch.toLowerCase()) || node.code.includes(coaSearch);
              if (!match && node.children.length === 0) return null;
          }
          const hasChildren = node.children.length > 0;
          const isExpanded = expandedNodes[node.id];
          const isGroup = node.level === 'group' || node.level === 'class';
          return (
              <div key={node.id}>
                  <div className={`flex items-center justify-between p-3 border-b border-gray-800 hover:bg-gray-800/50 transition-colors ${node.level === 'class' ? 'bg-gray-900/80 font-bold' : ''}`} style={{ paddingLeft: `${depth * 20 + 12}px` }}>
                      <div className="flex items-center gap-3 flex-1 overflow-hidden">
                          <div className="w-5 flex justify-center">{hasChildren && (<button onClick={() => toggleNode(node.id)} className="text-gray-500 hover:text-white transition-transform active:scale-90">{isExpanded || coaSearch ? <ChevronDown size={14} /> : <ChevronRight size={14} />}</button>)}</div>
                          <span className={`font-mono text-xs ${isGroup ? 'text-gray-400' : 'text-gray-500'} w-12 shrink-0`}>{node.code}</span>
                          {editingAccId === node.id ? (
                                <div className="flex gap-2 flex-1"><input className="w-full px-2 py-1 bg-gray-950 border border-blue-500 rounded text-sm text-white" value={editingAccName} onChange={e => setEditingAccName(e.target.value)} autoFocus /><button onClick={saveEditingAcc} className="text-emerald-500"><Check size={16} /></button><button onClick={cancelEditingAcc} className="text-red-500"><X size={16} /></button></div>
                          ) : (
                              <div className="flex items-center gap-2 truncate">{isGroup && <Folder size={14} className="text-blue-500/50" />}<span className={`${isGroup ? 'text-gray-200' : 'text-gray-400'} truncate`}>{node.name}</span></div>
                          )}
                      </div>
                      <div className="flex items-center gap-4 pl-4">
                          <span className={`font-mono text-sm ${getBalanceColor(node)} ${isGroup ? 'font-bold' : ''}`}>{node.totalBalance.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => goToSOA(node.id)} className="p-1.5 text-gray-500 hover:text-blue-400 hover:bg-gray-800 rounded transition-colors" title="View Ledger">
                                  <FileText size={14} />
                              </button>
                              <button onClick={() => startEditingAcc(node)} className="p-1.5 text-gray-600 hover:text-blue-400 hover:bg-gray-800 rounded transition-colors"><Pencil size={14} /></button>
                              {!node.isSystem && !hasChildren && (
                                  <button onClick={() => handleDelete('ACCOUNT', node.id)} className="p-1.5 text-gray-600 hover:text-red-400 hover:bg-gray-800 rounded transition-colors"><Trash2 size={14} /></button>
                              )}
                          </div>
                      </div>
                  </div>
                  {(isExpanded || coaSearch) && hasChildren && (<div className="border-l border-gray-800 ml-4 animate-fade-in">{renderTreeNodes(node.children, depth + 1)}</div>)}
              </div>
          );
      });
  };

  const filteredParties = state.parties.filter(p => 
      p.name.toLowerCase().includes(partySearch.toLowerCase()) || 
      p.email?.toLowerCase().includes(partySearch.toLowerCase()) ||
      p.phone?.includes(partySearch)
  );

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
          <div><h1 className="text-2xl font-bold text-gray-100">Settings</h1><p className="text-sm text-gray-400">System configuration and data management</p></div>
          <div className="flex gap-2 flex-wrap justify-end">
               <button onClick={handleBackup} className="flex items-center gap-2 bg-indigo-900/40 hover:bg-indigo-900/60 text-indigo-300 px-4 py-2 rounded-lg text-sm font-medium border border-indigo-900/50 transition-all hover:scale-105 active:scale-95"><Database size={16} /> Backup</button>
               <div className="relative"><input type="file" accept=".json" ref={backupInputRef} onChange={handleRestore} className="hidden" id="json-restore"/><label htmlFor="json-restore" className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-200 px-4 py-2 rounded-lg text-sm font-medium border border-gray-700 cursor-pointer transition-all hover:scale-105 active:scale-95"><FileJson size={16} /> Restore</label></div>
               <button onClick={handleExcelExport} className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-300 px-4 py-2 rounded-lg text-sm font-medium border border-green-900/50 transition-all hover:scale-105 active:scale-95"><FileSpreadsheet size={16} /> Export</button>
               <div className="relative"><input type="file" accept=".xlsx" ref={excelInputRef} onChange={handleExcelImport} className="hidden" id="excel-restore"/><label htmlFor="excel-restore" className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-200 px-4 py-2 rounded-lg text-sm font-medium border border-gray-700 cursor-pointer transition-all hover:scale-105 active:scale-95"><Upload size={16} /> Import</label></div>
          </div>
      </div>

      <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
          {['coa', 'profile', 'parties', 'recurring', 'templates', 'migration', 'danger'].map(t => (
              <button key={t} onClick={() => setActiveTab(t as Tab)} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all capitalize active:scale-95 ${activeTab === t ? 'bg-primary text-white shadow-lg shadow-blue-900/20' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                  {t === 'coa' && <Book size={16}/>} 
                  {t === 'recurring' && <Repeat size={16}/>} 
                  {t === 'profile' && <Building2 size={16}/>} 
                  {t === 'parties' && <Users size={16}/>} 
                  {t === 'templates' && <LayoutGrid size={16}/>} 
                  {t === 'migration' && <ArrowRightLeft size={16}/>} 
                  {t === 'danger' && <AlertTriangle size={16}/>}
                  {t === 'templates' ? 'Shortcuts' : (t === 'coa' ? 'Chart of Accounts' : t)}
              </button>
          ))}
      </div>

      {activeTab === 'profile' && (
          <div className="max-w-2xl bg-gray-900 p-6 rounded-2xl border border-gray-800 animate-fade-in shadow-xl">
              <div className="flex justify-between items-start mb-6">
                <h3 className="text-lg font-bold text-white flex items-center gap-2"><Building2 size={20} className="text-primary"/> Business Profile</h3>
                <div className="px-3 py-1 bg-gold-900/20 text-gold-400 border border-gold-500/30 rounded-lg text-xs font-bold uppercase flex items-center gap-2">
                    <Globe size={12} /> Base Currency: {baseCurrency}
                </div>
              </div>
              <form onSubmit={handleSaveProfile} className="space-y-4">
                  <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Business Name</label>
                      <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={bizName} onChange={e => setBizName(e.target.value)} />
                  </div>
                  <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Address</label>
                      <textarea className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary resize-none h-20" value={bizAddress} onChange={e => setBizAddress(e.target.value)} />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Email</label>
                          <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={bizEmail} onChange={e => setBizEmail(e.target.value)} />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Phone</label>
                          <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={bizPhone} onChange={e => setBizPhone(e.target.value)} />
                      </div>
                  </div>
                  <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Invoice Footer Note</label>
                      <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={bizFooter} onChange={e => setBizFooter(e.target.value)} placeholder="e.g. Thank you for your business" />
                  </div>
                  <button className="w-full py-3 bg-primary hover:bg-blue-600 text-white rounded-lg font-bold shadow-lg shadow-blue-900/30 active:scale-95 transition-transform">Save Profile</button>
              </form>
          </div>
      )}

      {activeTab === 'migration' && (
          <div className="max-w-2xl mx-auto space-y-6 animate-fade-in">
              <div className="bg-orange-900/20 border border-orange-500/30 p-6 rounded-2xl">
                  <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2"><ArrowRightLeft size={24} className="text-orange-500" /> Transfer Country / Currency</h3>
                  <p className="text-sm text-gray-400 mb-6">
                      Use this wizard to permanently migrate your entire financial history to a new base currency. 
                      This is useful if you move countries or change your primary reporting currency.
                  </p>

                  <form onSubmit={handleMigration} className="space-y-6">
                      <div className="grid grid-cols-2 gap-4">
                          <div className="p-4 bg-gray-900 rounded-xl border border-gray-800">
                              <span className="block text-xs font-bold text-gray-500 uppercase mb-1">Current Base</span>
                              <span className="text-2xl font-bold text-white">{baseCurrency}</span>
                          </div>
                          <div className="flex flex-col justify-end">
                              <label className="block text-xs font-bold text-orange-400 uppercase mb-1">Target Currency</label>
                              <select 
                                  className="w-full px-4 py-3 bg-gray-950 text-white border border-gray-700 rounded-xl outline-none focus:border-orange-500"
                                  value={migrationTarget}
                                  onChange={e => setMigrationTarget(e.target.value as CurrencyCode)}
                                  required
                              >
                                  <option value="">Select...</option>
                                  {CURRENCIES.filter(c => c.code !== baseCurrency).map(c => (
                                      <option key={c.code} value={c.code}>{c.code} - {c.name}</option>
                                  ))}
                              </select>
                          </div>
                      </div>

                      {migrationTarget && (
                          <div className="bg-gray-900 p-4 rounded-xl border border-gray-800 animate-fade-in">
                              <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Conversion Rate</label>
                              <div className="flex items-center gap-3">
                                  <span className="text-white font-mono">1 {baseCurrency} = </span>
                                  <input 
                                      type="number" step="0.0001" 
                                      className="w-32 px-3 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-orange-500 font-bold"
                                      value={migrationRate}
                                      onChange={e => setMigrationRate(e.target.value)}
                                      placeholder="0.00"
                                      required
                                  />
                                  <span className="text-white font-mono">{migrationTarget}</span>
                              </div>
                              <p className="text-xs text-gray-500 mt-2">
                                  All historical transaction amounts, asset values, and budgets will be multiplied by this rate.
                              </p>
                          </div>
                      )}

                      <div className="pt-4 border-t border-orange-500/20">
                          <label className="block text-xs font-bold text-red-400 uppercase mb-1">Confirmation</label>
                          <input 
                              type="text" 
                              className="w-full px-4 py-3 bg-gray-950 text-white border border-gray-700 rounded-xl outline-none focus:border-red-500 placeholder-gray-700" 
                              value={migrationConfirm} 
                              onChange={e => setMigrationConfirm(e.target.value)} 
                              placeholder="Type 'CONFIRM' to execute"
                              required
                          />
                      </div>

                      <button className="w-full py-4 bg-orange-600 hover:bg-orange-700 text-white rounded-xl font-bold shadow-lg shadow-orange-900/20 active:scale-95 transition-transform disabled:opacity-50 disabled:cursor-not-allowed">
                          Execute Migration
                      </button>
                  </form>
              </div>
          </div>
      )}

      {activeTab === 'parties' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fade-in">
              <div className="bg-gray-900 p-6 rounded-2xl border border-gray-800 shadow-xl">
                  <h3 className="text-lg font-bold text-white mb-4">Add Party</h3>
                  <form onSubmit={handleAddParty} className="space-y-4">
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Name</label>
                          <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={partyName} onChange={e => setPartyName(e.target.value)} required placeholder="Client or Vendor Name" />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Type</label>
                          <select className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={partyType} onChange={e => setPartyType(e.target.value as PartyType)}>
                              <option value="vendor">Vendor (Supplier)</option>
                              <option value="customer">Customer (Client)</option>
                              <option value="employee">Employee</option>
                              <option value="other">Other</option>
                          </select>
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Phone</label>
                          <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={partyPhone} onChange={e => setPartyPhone(e.target.value)} placeholder="+974..." />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Email</label>
                          <input className="w-full px-4 py-2 bg-gray-950 text-white border border-gray-700 rounded-lg outline-none focus:border-primary" value={partyEmail} onChange={e => setPartyEmail(e.target.value)} placeholder="contact@..." />
                      </div>
                      <div className="p-3 bg-blue-900/20 border border-blue-500/30 rounded-lg text-xs text-blue-300">
                          <p>
                             New account will be created under:<br/>
                             <b>11900 - Parties (Unified AR/AP)</b>
                          </p>
                      </div>
                      <button className="w-full py-3 bg-primary hover:bg-blue-600 text-white rounded-lg font-bold shadow-lg shadow-blue-900/30 active:scale-95 transition-transform">Create Entity</button>
                  </form>
              </div>
              <div className="md:col-span-2 space-y-4">
                  <div className="flex justify-between items-center mb-2">
                        <h4 className="text-sm font-bold text-gray-400 uppercase tracking-widest">Existing Parties</h4>
                        <div className="relative w-full max-w-xs">
                            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                className="w-full pl-9 pr-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-sm text-white focus:border-primary outline-none transition-all placeholder-gray-600" 
                                placeholder="Search parties..." 
                                value={partySearch}
                                onChange={e => setPartySearch(e.target.value)}
                            />
                        </div>
                  </div>
